// --- Error Boundary ---
class ErrorBoundary extends Component {
  constructor(props){super(props);this.state={hasError:false};}
  static getDerivedStateFromError(){return{hasError:true};}
  componentDidCatch(error, info){console.error("MARCH MAYHEM CRASH:",error,info);this.setState({errorMsg:error?.toString(),errorStack:info?.componentStack});}
  render(){if(this.state.hasError)return <div style={{background:"#0B1120",minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",padding:20}}><div style={{textAlign:"center",maxWidth:400}}><div style={{fontSize:60,marginBottom:12}}>😵</div><div style={{color:"#FF4757",fontSize:26,fontWeight:700}}>Something broke</div><div style={{color:"#7B8CA8",fontSize:17,marginTop:8,marginBottom:12}}>Try refreshing. Your data is saved.</div>{this.state.errorMsg&&<div style={{background:"#1E3050",borderRadius:8,padding:12,marginBottom:12,textAlign:"left",fontSize:11,color:"#FF6B35",fontFamily:"monospace",wordBreak:"break-all",maxHeight:200,overflow:"auto"}}>{this.state.errorMsg}<br/>{this.state.errorStack?.slice(0,500)}</div>}<button onClick={()=>{this.setState({hasError:false});window.location.reload();}} style={{background:"#FF6B35",color:"#fff",border:"none",borderRadius:8,padding:"12px 24px",fontSize:18,fontWeight:700,cursor:"pointer"}}>Refresh</button><br/><button onClick={()=>{try{localStorage.clear();}catch(e){}window.location.reload();}} style={{background:"#1E3050",color:"#7B8CA8",border:"none",borderRadius:8,padding:"12px 24px",fontSize:14,fontWeight:700,cursor:"pointer",marginTop:8}}>Clear Cache + Refresh</button></div></div>;return this.props.children;}
}

