function Logo({ name, size = 36, style: sx }) {
  const [err, setErr] = useState(false);
  const url = LOGOS[name];
  const tc = TEAM_COLORS[name] || "#1E3050";
  const fallback = <div style={{ width: size, height: size, borderRadius: "50%", background: tc, display: "flex", alignItems: "center", justifyContent: "center", fontSize: size * 0.38, fontWeight: 800, color: "#fff", flexShrink: 0, textShadow: "0 1px 2px rgba(0,0,0,0.3)", ...sx }}>{(name || "?").charAt(0)}</div>;
  if (!url || err) return fallback;
  return <img src={url} alt={name} onError={() => setErr(true)} style={{ width: size, height: size, objectFit: "contain", flexShrink: 0, ...sx }} />;
}

