function hype(s) {
  if (s===1) return { l: "Tournament favorite", e: "👑", t: "ELITE", bg: "#FFD70020" };
  if (s===2) return { l: "Title contender", e: "🔥", t: "ELITE", bg: "#FF6B3520" };
  if (s===3) return { l: "Sweet 16 lock", e: "💪", t: "STRONG", bg: "#00D4AA20" };
  if (s===4) return { l: "Dangerous squad", e: "⚡", t: "STRONG", bg: "#3B82F620" };
  if (s===5) return { l: "Sleeper pick", e: "😤", t: "SOLID", bg: "#A855F720" };
  if (s===6) return { l: "Second weekend potential", e: "📈", t: "SOLID", bg: "#A855F720" };
  if (s<=8) return { l: "Coin flip matchup", e: "🎲", t: "WILD", bg: "#FBBF2420" };
  if (s<=10) return { l: "Upset alert", e: "⚠️", t: "WILD", bg: "#F43F5E20" };
  if (s<=12) return { l: "Cinderella candidate", e: "👟", t: "LONGSHOT", bg: "#06B6D420" };
  if (s<=14) return { l: "Madness maker", e: "🤯", t: "LONGSHOT", bg: "#8B5CF620" };
  return { l: "Miracle run?", e: "🙏", t: "PRAYER", bg: "#FF475720" };
}

function grade(teams) {
  // Power score: lower seeds = more points. 1-seed=16pts, 16-seed=1pt
  const power = teams.reduce((a,t)=>a+(17-t.seed),0);
  const avg = teams.reduce((a,t)=>a+t.seed,0)/teams.length;
  const has1 = teams.some(t=>t.seed===1);
  const has2 = teams.some(t=>t.seed<=2);
  // Power range in 8-team snake: ~60-76
  if (power>=72) return { g: "A+", d: "Stacked", c: "#00D4AA", avg: avg.toFixed(1) };
  if (power>=70) return { g: "A", d: has1?"Led by a 1-seed":"Top-heavy", c: "#00D4AA", avg: avg.toFixed(1) };
  if (power>=68) return { g: "A-", d: has1?"Anchor + depth":"Balanced", c: "#00D4AA", avg: avg.toFixed(1) };
  if (power>=66) return { g: "B+", d: has2?"Contender":"Solid mid", c: "#FBBF24", avg: avg.toFixed(1) };
  if (power>=64) return { g: "B", d: "Gritty", c: "#FBBF24", avg: avg.toFixed(1) };
  return { g: "B-", d: "Underdog build", c: "#FF6B35", avg: avg.toFixed(1) };
}

// Win % = alive teams / total alive teams (spread equalizes all seeds)
// --- ACHIEVEMENTS ENGINE ---
function calcAchievements(state, playerId) {
  const badges = [];
  const myGames = state.games.filter(g => g.completed && g.transferInfo);
  const mysteals = myGames.filter(g => g.transferInfo.stolen && g.transferInfo.to === state.players[playerId]?.name);
  const stolenFrom = myGames.filter(g => g.transferInfo.stolen && g.transferInfo.from === state.players[playerId]?.name);
  const myCovers = myGames.filter(g => !g.transferInfo.stolen && g.transferInfo.to === state.players[playerId]?.name);
  const myTeams = state.teams.filter(t => t.currentOwner === playerId);
  const alive = myTeams.filter(t => t.alive);

  // First Blood — first steal in the tournament
  if (mysteals.length > 0) {
    const firstSteal = myGames.find(g => g.transferInfo.stolen && g.transferInfo.to === state.players[playerId]?.name);
    if (firstSteal && myGames.filter(g => g.transferInfo.stolen).indexOf(firstSteal) === 0)
      badges.push({ icon: "🩸", name: "First Blood", desc: "First steal of the tournament" });
  }

  // Highway Robbery — stole a 1 or 2 seed
  if (mysteals.some(g => { const w = state.teams.find(t => t.id === g.winnerId); return w && w.seed <= 2; }))
    badges.push({ icon: "🏴‍☠️", name: "Highway Robbery", desc: "Stole a top-2 seed" });

  // Iron Grip — held a team through 3+ resolved rounds
  const longHolds = state.teams.filter(t => t.currentOwner === playerId && t.originalOwner === playerId && t.alive);
  const resolvedRounds = new Set(myGames.map(g => g.round)).size;
  if (longHolds.length > 0 && resolvedRounds >= 3)
    badges.push({ icon: "🔒", name: "Iron Grip", desc: "Held an original team through 3+ rounds" });

  // Serial Stealer — 3+ steals total
  if (mysteals.length >= 3)
    badges.push({ icon: "🐍", name: "Serial Stealer", desc: `${mysteals.length} steals total` });

  // Untouchable — 0 teams stolen from you all tournament (min 1 resolved round)
  if (stolenFrom.length === 0 && myGames.length >= 4)
    badges.push({ icon: "🛡️", name: "Untouchable", desc: "Nobody has stolen from you" });

  // Survivor — came back from having only 1-2 alive teams
  if (alive.length >= 4 && myTeams.filter(t => !t.alive).length >= 4)
    badges.push({ icon: "🔥", name: "Survivor", desc: "Still strong after heavy losses" });

  // Underdog King — won 3+ spread battles as underdog owner
  const dogWins = myGames.filter(g => {
    const dog = state.teams.find(t => t.id === g.team2Id);
    return dog && dog.currentOwner === playerId && !g.transferInfo.stolen;
  });
  if (dogWins.length >= 3)
    badges.push({ icon: "👑", name: "Underdog King", desc: `${dogWins.length} spread wins as underdog` });

  return badges;
}

// --- STREAK TRACKER ---
function calcStreak(state, playerId) {
  const pName = state.players[playerId]?.name;
  const resolved = state.games.filter(g => g.completed && g.transferInfo).sort((a, b) => (a.transferInfo?.ts || 0) - (b.transferInfo?.ts || 0));
  let streak = 0;
  for (let i = resolved.length - 1; i >= 0; i--) {
    const g = resolved[i];
    const ti = g.transferInfo;
    const involved = ti.from === pName || ti.to === pName;
    if (!involved) continue;
    const won = ti.stolen ? ti.to === pName : ti.from === pName || ti.to === pName;
    // "won" = you kept control or stole. "lost" = someone stole from you.
    const iWon = ti.stolen ? ti.to === pName : ti.to === pName;
    const iLost = ti.stolen && ti.from === pName;
    if (iWon && !iLost) streak++;
    else break;
  }
  return streak;
}

// --- TRASH TALK GENERATOR ---
function trashTalk(ti, margin, spread) {
  if (!ti.stolen) return null;
  const lines = [
    `${ti.to} just RIPPED ${ti.advancer} away from ${ti.from}. Brutal.`,
    `${ti.from} thought they were safe. They were not. ${ti.to} says thanks.`,
    `${ti.advancer} has a new owner and ${ti.from} has a new problem.`,
    `Didn't cover by ${Math.abs(margin - spread)} points. ${ti.to} eats.`,
    `${ti.from} in shambles. ${ti.to} just stole ${ti.advancer} for free.`,
  ];
  return lines[Math.floor(Math.random() * lines.length)];
}

function calcOdds(state) {
  const alive = state.teams.filter(t => t.alive);
  const total = alive.length;
  if (total === 0) return state.players.map(p => ({ ...p, pct: 0, teams: [] }));
  if (total === 1) {
    return state.players.map(p => ({
      ...p,
      pct: p.id === alive[0].currentOwner ? 100 : 0,
      teams: p.id === alive[0].currentOwner ? [{ name: alive[0].name, seed: alive[0].seed, pct: 100 }] : [],
    }));
  }
  const perTeam = 100 / total;
  return state.players.map(p => {
    const myAlive = alive.filter(t => t.currentOwner === p.id);
    const pct = Math.round((myAlive.length / total) * 1000) / 10;
    return {
      ...p,
      pct,
      teams: myAlive.map(t => ({ name: t.name, seed: t.seed, pct: Math.round(perTeam * 10) / 10 })).sort((a, b) => a.seed - b.seed),
    };
  }).sort((a, b) => b.pct - a.pct);
}

function spreadResult(g, teams) {
  if (g.winnerId==null||g.margin==null||g.team1Id==null||g.team2Id==null) return null;
  const favId=g.team1Id, dogId=g.team2Id;
  const fav=teams.find(t=>t.id===favId), dog=teams.find(t=>t.id===dogId);
  if (!fav||!dog) return null;
  const sv=Math.abs(g.spread||0);
  const favWon=g.winnerId===favId;
  const loserId=favWon?dogId:favId;
  const winnerId=g.winnerId;
  const winner=teams.find(t=>t.id===winnerId), loser=teams.find(t=>t.id===loserId);
  // Who wins the spread?
  let spreadWinner; // owner ID who controls advancing team
  if (sv===0) {
    // No spread: game winner's owner keeps control
    spreadWinner = winner.currentOwner;
  } else if (favWon) {
    // Fav won: did they cover? margin must be GREATER than spread (tie → underdog)
    spreadWinner = g.margin > sv ? fav.currentOwner : dog.currentOwner;
  } else {
    // Underdog won outright: underdog owner always wins spread
    spreadWinner = dog.currentOwner;
  }
  const stolen = spreadWinner !== winner.currentOwner;
  return { favId, dogId, fav, dog, sv, favWon, winnerId, loserId, winner, loser, spreadWinner, stolen };
}

// Odds shift preview helper
function oddsShift(pv, state) {
  const alNow=state.teams.filter(x=>x.alive).length;
  if(alNow<=1)return null;
  const curPcts={};state.players.forEach(p=>{curPcts[p.id]=Math.round((state.teams.filter(x=>x.alive&&x.currentOwner===p.id).length/alNow)*1000)/10;});
  const newAl=alNow-1;
  const newPcts={};state.players.forEach(p=>{let c=state.teams.filter(x=>x.alive&&x.currentOwner===p.id&&x.id!==pv.loserId).length;if(pv.stolen&&p.id===pv.spreadWinner)c++;if(pv.stolen&&p.id===pv.winner.currentOwner&&p.id!==pv.spreadWinner)c--;newPcts[p.id]=Math.round((c/newAl)*1000)/10;});
  return state.players.filter(p=>newPcts[p.id]!==curPcts[p.id]).sort((a,b)=>Math.abs(newPcts[b.id]-curPcts[b.id])-Math.abs(newPcts[a.id]-curPcts[a.id])).map(p=>({...p,cur:curPcts[p.id],next:newPcts[p.id],diff:Math.round((newPcts[p.id]-curPcts[p.id])*10)/10}));
}

// --- SUPABASE = SINGLE SOURCE OF TRUTH ---
// Every read goes to Supabase first. localStorage is just a speed cache.
// Every write goes to Supabase FIRST, then caches locally.
async function supaRead(key) {
  if (!SUPA_REST) return null;
  try {
    const ctrl=new AbortController();
    const tm=setTimeout(()=>ctrl.abort(),5000);
    const r = await fetch(SUPA_REST+"?key=eq."+encodeURIComponent(key)+"&select=value", {headers:{"apikey":SUPA_KEY,"Authorization":"Bearer "+SUPA_KEY},signal:ctrl.signal});
    clearTimeout(tm);
    if (!r.ok) { console.error("supaRead "+key+" HTTP "+r.status); return null; }
    const rows = await r.json();
    const val = rows?.[0]?.value;
    if (val === undefined || val === null) return null;
    // Cache non-empty results locally for offline fallback
    if (Object.keys(val).length > 0) { try { localStorage.setItem("cache-"+key, JSON.stringify(val)); } catch(e){} }
    return val; // Return {} as valid — means "empty, fresh start"
  } catch(e) { console.error("supaRead error:", e); return null; }
}
const _retryQueue=[];
let _retrying=false;
async function supaWrite(key, value) {
  // Always cache locally first (optimistic)
  try { localStorage.setItem("cache-"+key, JSON.stringify(value)); } catch(e){}
  if (!SUPA_REST) return false;
  try {
    const r = await fetch(SUPA_REST, {method:"POST",headers:SUPA_HEADERS,body:JSON.stringify({key,value,updated_at:new Date().toISOString()})});
    if (r.ok) return true;
    console.error("supaWrite "+key+" HTTP "+r.status);
    _retryQueue.push({key,value,attempts:0});
    _startRetry();
    return false;
  } catch(e) {
    console.error("supaWrite error:", e);
    _retryQueue.push({key,value,attempts:0});
    _startRetry();
    return false;
  }
}
function _startRetry(){
  if(_retrying)return;_retrying=true;
  const iv=setInterval(async()=>{
    if(_retryQueue.length===0){clearInterval(iv);_retrying=false;return;}
    const item=_retryQueue[0];
    try{
      const r=await fetch(SUPA_REST,{method:"POST",headers:SUPA_HEADERS,body:JSON.stringify({key:item.key,value:item.value,updated_at:new Date().toISOString()})});
      if(r.ok){_retryQueue.shift();console.log("Retry succeeded for",item.key);}
      else{item.attempts++;if(item.attempts>10)_retryQueue.shift();}
    }catch(e){item.attempts++;if(item.attempts>10)_retryQueue.shift();}
  },10000);
}
function cacheRead(key) { try { const d=localStorage.getItem("cache-"+key); return d?JSON.parse(d):null; } catch(e) { return null; } }

// Game state
async function load() {
  const remote = await supaRead("state");
  if (remote !== null) return Object.keys(remote).length > 0 ? remote : null; // {} = fresh, use INIT
  return cacheRead("state"); // null = network error, use cache
}
async function save(s) {
  // Never save per-device fields to shared state
  const {lastPlayerId, ...shared} = s;
  s = shared;
  const remote = await supaRead("state");
  if (remote && Object.keys(remote).length > 0) {
    // MERGE FEED: combine + dedupe by ts+detail
    if (remote.feed && s.feed) {
      const seen = new Set(s.feed.map(f => f.ts + "_" + f.detail));
      const remoteMissing = remote.feed.filter(f => !seen.has(f.ts + "_" + f.detail));
      s = {...s, feed: [...remoteMissing, ...s.feed].sort((a,b) => a.ts - b.ts)};
    }
    // MERGE GAMES: take whichever has more completed games (commissioner wins)
    const localDone = (s.games||[]).filter(g => g.completed).length;
    const remoteDone = (remote.games||[]).filter(g => g.completed).length;
    if (remoteDone > localDone) {
      s = {...s, games: remote.games, teams: remote.teams, currentRound: Math.max(s.currentRound||0, remote.currentRound||0)};
    }
    // MERGE ROUND: always take the higher round
    if ((remote.currentRound||0) > (s.currentRound||0)) {
      s = {...s, currentRound: remote.currentRound};
    }
  }
  await supaWrite("state", s);
}
// Reveals — LOCAL ONLY (each device, one-time)
function loadReveals() { try { const d=localStorage.getItem("mm-reveals-final"); return d?JSON.parse(d):null; } catch(e){ return {}; } }
function saveReveals(seen) { try { localStorage.setItem("mm-reveals-final", JSON.stringify(seen)); } catch(e){} }
// Avatars
async function loadAvatars() {
  const remote = await supaRead("avatars");
  if (remote !== null) return Object.keys(remote).length > 0 ? remote : null;
  return cacheRead("avatars");
}
async function saveAvatars(av) {
  // Read-merge-write: don't overwrite other people's avatars
  const remote = await supaRead("avatars") || {};
  const merged = {...remote, ...av};
  await supaWrite("avatars", merged);
}

const ESPN="https://site.api.espn.com/apis/site/v2/sports/basketball/mens-college-basketball/scoreboard";
const _scoreCache=(()=>{try{const raw=localStorage.getItem("espn-cache");if(!raw||raw.length>500000){localStorage.removeItem("espn-cache");return{};}return JSON.parse(raw)}catch(e){localStorage.removeItem("espn-cache");return{}}})();
function _saveCache(){try{localStorage.setItem("espn-cache",JSON.stringify(_scoreCache))}catch(e){}}
async function fetchScoresForDay(d){
  try{
    const u=d?`${ESPN}?dates=${d}&groups=100&limit=100`:`${ESPN}?groups=100&limit=100`;
    const r=await fetch(u);if(!r.ok)return[];
    const data=await r.json();
    const results=(data.events||[]).map(ev=>{const c=ev.competitions?.[0];const ts=(c?.competitors||[]).map(x=>({name:x.team?.displayName||"",abbr:x.team?.abbreviation||"",score:parseInt(x.score)||0,home:x.homeAway==="home"}));return{id:ev.id,name:ev.shortName||"",date:ev.date,status:c?.status?.type?.name||"",detail:c?.status?.type?.shortDetail||"",clock:c?.status?.displayClock||"",period:c?.status?.period||0,home:ts.find(t=>t.home),away:ts.find(t=>!t.home),teams:ts,spread:c?.odds?.[0]?.details||""};});
    // Cache FINAL results permanently so we never re-fetch settled days
    if(d){const allFinal=results.every(r=>r.status==="STATUS_FINAL");if(allFinal&&results.length>0){_scoreCache[d]=results;_saveCache();}}
    return results;
  }catch(e){return[];}
}
function getDayStr(offset){const d=new Date();d.setDate(d.getDate()+offset);return d.toISOString().slice(0,10).replace(/-/g,"");}
async function fetchScores(singleDay){
  if(singleDay)return fetchScoresForDay(singleDay);
  // Quick fetch: today + yesterday + tomorrow (3 calls max)
  let all=[];const seen=new Set();
  for(const d of [getDayStr(0),getDayStr(-1),getDayStr(1)]){
    const cached=_scoreCache[d];
    const results=cached||await fetchScoresForDay(d);
    for(const r of results){if(!seen.has(r.id)){seen.add(r.id);all.push(r);}}
  }
  return all;
}
async function fetchScoresDeep(){
  // Scan tournament window: March 18 → April 8, 2026
  const start=new Date("2026-03-18"),end=new Date("2026-04-08"),today=new Date();
  const last=end<today?end:today;
  let all=[];const seen=new Set();
  for(let d=new Date(start);d<=last;d.setDate(d.getDate()+1)){
    const ds=d.toISOString().slice(0,10).replace(/-/g,"");
    if(_scoreCache[ds]){for(const r of _scoreCache[ds]){if(!seen.has(r.id)){seen.add(r.id);all.push(r);}}continue;}
    const results=await fetchScoresForDay(ds);
    for(const r of results){if(!seen.has(r.id)){seen.add(r.id);all.push(r);}}
  }
  return all;
}
function isLive(status){return status==="STATUS_IN_PROGRESS"||status==="STATUS_HALFTIME";}
function fz(draftTeam,espnName,espnAbbr){
  if(!draftTeam||(!espnName&&!espnAbbr))return false;
  // If draft team has an ESPN abbreviation, ONLY match on that — no fuzzy fallback
  if(draftTeam.espn){
    return espnAbbr&&draftTeam.espn.toUpperCase()===espnAbbr.toUpperCase();
  }
  // Fallback: fuzzy name match for teams without ESPN codes
  const x=(draftTeam.name||draftTeam).toString().toLowerCase().replace(/[^a-z0-9]/g,"");
  const y=(espnName||"").toLowerCase().replace(/[^a-z0-9]/g,"");
  return x.length>3&&y.length>3&&(x.includes(y)||y.includes(x));
}
function timeAgo(ts){if(!ts)return"";const s=Math.floor((Date.now()-ts)/1000);if(s<60)return"just now";if(s<3600)return`${Math.floor(s/60)}m ago`;if(s<86400)return`${Math.floor(s/3600)}h ago`;return`${Math.floor(s/86400)}d ago`;}
function fmtDate(d,t){if(!d)return"";const months=["Jan","Feb","March","April","May","June","July","Aug","Sept","Oct","Nov","Dec"];const parts=d.split("-");const m=parseInt(parts[1])-1,day=parseInt(parts[2]);const suf=day===1||day===21||day===31?"st":day===2||day===22?"nd":day===3||day===23?"rd":"th";let str=`${months[m]} ${day}${suf}`;if(t){const [h,mn]=t.split(":").map(Number);const ampm=h>=12?"pm":"am";const h12=h===0?12:h>12?h-12:h;str+=` ${h12}:${mn.toString().padStart(2,"0")}${ampm}`;}return str;}

// --- AUTO-BRACKET: generate next round matchups from bracket structure ---
function generateNextRound(state) {
  const rd = state.currentRound;
  const curGames = state.games.filter(g => g.round === rd);
  if (curGames.some(g => !g.completed)) return null; // Not all games done
  // Group games by bracket position (pairs of games feed into next round)
  const winners = curGames.map(g => {
    const wt = state.teams.find(t => t.id === g.winnerId);
    return wt;
  }).filter(Boolean);
  if (winners.length < 2) return null;
  // Pair winners: game 0 winner vs game 1 winner, game 2 vs game 3, etc.
  const nextGames = [];
  for (let i = 0; i < winners.length; i += 2) {
    if (!winners[i + 1]) break;
    const w1 = winners[i], w2 = winners[i + 1];
    // Higher seed is the favorite (team1Id = favorite)
    const fav = w1.seed <= w2.seed ? w1 : w2;
    const dog = w1.seed <= w2.seed ? w2 : w1;
    nextGames.push({
      id: Date.now() + i,
      round: rd + 1,
      team1Id: fav.id,
      team2Id: dog.id,
      spread: 0, // Will be updated when lines come out
      winnerId: null, margin: null, completed: false, transferInfo: null,
      gameDate: "", gameTime: ""
    });
  }
  return {
    ...state,
    games: [...state.games, ...nextGames],
    currentRound: rd + 1,
    feed: [...(state.feed || []), {
      type: "system", team: "",
      detail: "Round " + (rd + 2) + " matchups are set! " + nextGames.length + " games.",
      round: ["Round 1","Round 2","Sweet 16","Elite 8","Final Four","Championship"][rd + 1] || "Next Round",
      matchup: "", ts: Date.now()
    }]
  };
}

// --- APP SHELL — Bottom nav + transitions ---
export default function App() {
  const [state, setState] = useState(INIT);
  const [view, setView] = useState("splash");
  const [player, setPlayer] = useState(null);
  const [loaded, setLoaded] = useState(false);
  const [revealSeen, setRevealSeen] = useState({});
  const [recapSeen, setRecapSeen] = useState(()=>{try{return JSON.parse(localStorage.getItem("mm-recap-seen")||"{}")}catch(e){return{}}});
  const [showRecap, setShowRecap] = useState(false);
  const [avatars, setAvatars] = useState({});
  const [eg, setEg] = useState(null);
  const [scores, setScores] = useState([]);
  const [sl, setSl] = useState(false);
  const [trans, setTrans] = useState(false); // false | "out" | "in"
  const [lastRefresh, setLastRefresh] = useState(null);
  const [toast, setToast] = useState(null);
  const [flash, setFlash] = useState(null);
  const [teamDetail, setTeamDetail] = useState(null);
  const [notification, setNotification] = useState(null);
  const [obituary, setObituary] = useState(null);
  const prevAliveRef = useRef({}); // {type:"steal"|"cover", team, from, to, detail}
  const prevScoresRef = useRef([]);
  const st = useRef(null);

  useEffect(()=>{
    // Clean stale keys from old builds + force fresh load
    try{["mm-final","mm-avatars"].forEach(k=>localStorage.removeItem(k));}catch(e){}
    (async()=>{
      const rv = loadReveals();
      if(rv)setRevealSeen(rv);
      const s = await load();
      if(s)setState(s);
      const av = await loadAvatars();
      if(av)setAvatars(av);
      setLoaded(true);
      // Initialize alive counts so obituary doesn't false-trigger
      const aliveInit={};
      (s||INIT).players.forEach(p=>{
        aliveInit[p.id]=(s||INIT).teams.filter(t=>t.alive&&t.currentOwner===p.id).length;
      });
      prevAliveRef.current=aliveInit;
    })();
  },[]);

  // Sync from Supabase every 5 seconds — NEVER overwrite richer local data
  const stateRef = useRef(state);
  const avatarsRef = useRef(avatars);
  useEffect(()=>{stateRef.current=state;},[state]);
  useEffect(()=>{avatarsRef.current=avatars;},[avatars]);
  useEffect(()=>{
    if(!SUPA_REST)return;
    const poll = async()=>{
      try{
        const [s,a] = await Promise.all([supaRead("state"),supaRead("avatars")]);
        // Only accept remote state if it has actual content AND more/equal completed games
        if(s && Object.keys(s).length > 0) {
          const localGames = (stateRef.current.games||[]).filter(g=>g.completed).length;
          const remoteGames = (s.games||[]).filter(g=>g.completed).length;
          const localFeed = (stateRef.current.feed||[]).length;
          const remoteFeed = (s.feed||[]).length;
          // Accept if remote has more game progress OR more feed items
          if(remoteGames >= localGames || remoteFeed > localFeed) {
            // Merge feed (don't lose local messages not yet synced)
            if(stateRef.current.feed && s.feed) {
              const seen = new Set(s.feed.map(f=>f.ts+"_"+f.detail));
              const localOnly = stateRef.current.feed.filter(f=>!seen.has(f.ts+"_"+f.detail));
              if(localOnly.length > 0) s.feed = [...s.feed, ...localOnly].sort((a,b)=>a.ts-b.ts);
            }
            if(JSON.stringify(stateRef.current)!==JSON.stringify(s)) {
              // Detect newly resolved games for notification
              const oldDone = new Set((stateRef.current.games||[]).filter(g=>g.completed).map(g=>g.id));
              const fresh = (s.games||[]).filter(g=>g.completed&&!oldDone.has(g.id)&&g.transferInfo);
              if(fresh.length>0){const g=fresh[0],ti=g.transferInfo;if(ti)setNotification({type:ti.stolen?"steal":"cover",team:ti.advancer,from:ti.from,to:ti.to,stolen:ti.stolen});}
              // Check for player elimination
              const prev=prevAliveRef.current;
              s.players.forEach(p=>{
                const wasAlive=prev[p.id]||8;
                const nowAlive=s.teams.filter(t=>t.alive&&t.currentOwner===p.id).length;
                if(wasAlive>0&&nowAlive===0&&!obituary){setTimeout(()=>setObituary(p),2000);}
                prev[p.id]=nowAlive;
              });
              prevAliveRef.current=prev;
              setState(s);
            }
          }
        }
        // Avatars: only accept if remote has MORE avatars than local
        if(a && Object.keys(a).length >= Object.keys(avatarsRef.current||{}).length) {
          if(JSON.stringify(avatarsRef.current)!==JSON.stringify(a)) setAvatars(a);
        }
      }catch(e){}
    };
    const i=setInterval(poll,5000);
    return()=>clearInterval(i);
  },[]);
  const P=useCallback((ns)=>{setState(ns);if(st.current)clearTimeout(st.current);st.current=setTimeout(()=>save(ns),300);},[]);
  const PN=useCallback((ns)=>{setState(ns);if(st.current)clearTimeout(st.current);save(ns);},[]);
  const refresh=useCallback(async(d)=>{setSl(true);const sc=await fetchScores(d||null);setScores(sc);setSl(false);setLastRefresh(Date.now());
    // Detect newly FINAL games involving alive teams
    if(prevScoresRef.current.length>0){
      const prevFinal=new Set(prevScoresRef.current.filter(s=>s.status==="STATUS_FINAL").map(s=>s.id));
      const newFinals=sc.filter(s=>s.status==="STATUS_FINAL"&&!prevFinal.has(s.id));
      for(const nf of newFinals){
        const myTeam=state.teams.find(t=>t.alive&&t.currentOwner===player?.id&&nf.teams.some(lt=>fz(t,lt.name,lt.abbr)));
        if(myTeam){setToast({game:nf,team:myTeam});setTimeout(()=>setToast(null),8000);break;}
      }
    }
    prevScoresRef.current=sc;
  },[state.teams,player]);

  useEffect(()=>{if(view==="bracket"||view==="warRoom"||view==="leaderboard"){refresh();const i=setInterval(()=>refresh(),30000);return()=>clearInterval(i);}}, [view,refresh]);

  // AUTO-RESOLVE: every 5 min, resolve any FINAL games automatically (waits for load)
  useEffect(()=>{
    if(!loaded)return;
    const autoResolve=async()=>{
      try{
        const sc=await fetchScores();
        const finals=sc.filter(s=>s.status==="STATUS_FINAL");
        if(finals.length===0)return;
        let s={...stateRef.current};
        let changed=false;
        for(const fin of finals){
          const game=s.games.find(g=>!g.completed&&g.team1Id!=null&&g.team2Id!=null&&(()=>{
            const t1=s.teams.find(t=>t.id===g.team1Id),t2=s.teams.find(t=>t.id===g.team2Id);
            return t1&&t2&&fin.teams.some(lt=>fz(t1,lt.name,lt.abbr))&&fin.teams.some(lt=>fz(t2,lt.name,lt.abbr));
          })());
          if(!game)continue;
          const t1=s.teams.find(t=>t.id===game.team1Id),t2=s.teams.find(t=>t.id===game.team2Id);
          const et1=fin.teams.find(lt=>fz(t1,lt.name,lt.abbr)),et2=fin.teams.find(lt=>fz(t2,lt.name,lt.abbr));
          if(!et1||!et2)continue;
          const winnerId=et1.score>et2.score?game.team1Id:game.team2Id;
          const margin=Math.abs(et1.score-et2.score);
          const spread=Math.abs(game.spread||0);
          const favWon=winnerId===game.team1Id;
          let spreadWinnerOwner;let stolen;
          if(spread===0){spreadWinnerOwner=s.teams.find(t=>t.id===winnerId).currentOwner;stolen=false;}
          else if(favWon){if(margin>spread){spreadWinnerOwner=t1.currentOwner;stolen=false;}else{spreadWinnerOwner=t2.currentOwner;stolen=true;}}
          else{spreadWinnerOwner=t2.currentOwner;stolen=false;}
          const loserId=winnerId===game.team1Id?game.team2Id:game.team1Id;
          const winner=s.teams.find(t=>t.id===winnerId);
          const fromName=s.players[winner.currentOwner].name;
          const toName=s.players[spreadWinnerOwner].name;
          game.completed=true;game.winnerId=winnerId;game.margin=margin;
          game.transferInfo={stolen,from:fromName,to:toName,advancer:winner.name};
          s.teams=s.teams.map(t=>{
            if(t.id===winnerId)return{...t,currentOwner:spreadWinnerOwner};
            if(t.id===loserId)return{...t,alive:false,eliminatedRound:s.currentRound||0};
            return t;
          });
          const RD=["Round 1","Round 2","Sweet 16","Elite 8","Final Four","Championship"][s.currentRound||0];
          s.feed=[...(s.feed||[]),{type:stolen?"transfer":"cover",team:winner.name,detail:winner.name+(stolen?" STOLEN by "+toName+" from "+fromName:" advances — "+toName+" keeps control")+" ("+et1.score+"-"+et2.score+", spread "+spread+")",round:RD,matchup:t1.name+" vs "+t2.name,ts:Date.now()+changed}];
          changed=true;
        }
        if(changed)save(s);
      }catch(e){console.error("autoResolve error:",e);}
    };
    const i=setInterval(autoResolve,300000); // 5 minutes
    setTimeout(autoResolve,3000); // Run 3s after load (not immediately)
    return()=>clearInterval(i);
  },[loaded]);

  // Check if any of current player's alive teams have live games
  const hasLive=useMemo(()=>{
    if(!player)return false;
    return scores.some(s=>isLive(s.status)&&state.teams.some(t=>t.alive&&t.currentOwner===player.id&&(fz(t,s.teams[0]?.name,s.teams[0]?.abbr)||fz(t,s.teams[1]?.name,s.teams[1]?.abbr))));
  },[scores,state.teams,player]);

  const triggerFlash=useCallback((type)=>{setFlash(type);setTimeout(()=>setFlash(null),600);},[]);
  useEffect(()=>{if(notification){const t=setTimeout(()=>setNotification(null),5000);return()=>clearTimeout(t);}},[notification]);

  const alive=state.teams.filter(t=>t.alive);
  // Show round recap once when a round completes + auto-advance
  useEffect(()=>{
    if(!loaded||!player)return;
    // Check ALL rounds — find the highest completed round not yet seen
    for(let rd=5;rd>=0;rd--){
      const rdGames=state.games.filter(g=>g.round===rd);
      if(rdGames.length>0&&rdGames.every(g=>g.completed)&&!recapSeen[rd]){
        setShowRecap(true);
        break;
      }
    }
    // Note: next round games are added manually with real ESPN matchups/spreads
    // Auto-advance only bumps currentRound, does NOT generate games
  },[state.games,loaded,player]);
  const champ=alive.length===1?alive[0]:null;
  const co=champ?state.players[champ.currentOwner]:null;

  const go=(v)=>{
    if(v===view)return;
    setTrans("out");
    setTimeout(()=>{
      setView(v);
      window.scrollTo(0,0);
      setTrans("in");
      setTimeout(()=>setTrans(false),300);
    },200);
  };
  const pick=(p)=>{setPlayer(p);try{localStorage.setItem("mm-my-player",String(p.id));}catch(e){}if(!avatars[p.id]&&avatars[p.id]!=="skip")go("avatar");else if(!revealSeen[p.id])go("reveal");else go("warRoom");};
  const markSeen=(pid)=>{const ns={...revealSeen,[pid]:true};setRevealSeen(ns);saveReveals(ns);};
  const setAvatar=async(pid,data)=>{
    const ns={...avatars,[pid]:data};setAvatars(ns);
    await saveAvatars(ns);
    // Refresh from Supabase to get ALL avatars (including other devices)
    const fresh=await supaRead("avatars");
    if(fresh)setAvatars(fresh);
  };

  // Auto-restore: URL param (?p=0) > localStorage > splash
  useEffect(()=>{
    if(!loaded||player)return;
    // Check URL param first: ?p=0 through ?p=7
    const params = new URLSearchParams(window.location.search);
    const urlP = params.get("p");
    let pid = urlP !== null ? parseInt(urlP) : null;
    // Fall back to localStorage
    if(pid === null) { try { const s=localStorage.getItem("mm-my-player"); if(s!==null) pid=parseInt(s); } catch(e){} }
    if(pid !== null && pid >= 0 && pid <= 7) {
      const p = state.players.find(pl=>pl.id===pid);
      if(p){
        setPlayer(p);
        try{localStorage.setItem("mm-my-player",String(pid));}catch(e){}
        if(avatars[p.id]&&revealSeen[p.id]) setView("warRoom");
        // Show yearbook if champion is crowned
        const aliveT=state.teams.filter(t=>t.alive);
        if(aliveT.length===1) setView("leaderboard");
      }
    }
  },[loaded]);

  if(!loaded) return <div style={{background:"#0B1120",minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center"}}><div style={{textAlign:"center"}}><div style={{fontSize:56,marginBottom:12,animation:"bounce 1s ease infinite"}}>🏀</div><div style={{color:"#FF6B35",fontSize:36,fontWeight:900,letterSpacing:6}}>MARCH MAYHEM</div><div style={{color:"#7B8CA8",marginTop:8}}>Loading your league...</div></div><style>{`@keyframes bounce{0%,100%{transform:translateY(0)}50%{transform:translateY(-12px)}}`}</style></div>;

  const showNav = !["splash","reveal","avatar"].includes(view);

  const content = {
    splash: <Splash go={go} />,
    select: <Sel state={state} champ={champ} co={co} pick={pick} go={go} revealSeen={revealSeen} avatars={avatars} />,
    avatar: <AvatarSetup player={player} onDone={(data)=>{setAvatar(player.id,data);if(!revealSeen[player.id])go("reveal");else go("warRoom");}} />,
    reveal: <Reveal state={state} player={player} onDone={()=>{markSeen(player.id);go("warRoom");}} />,
    warRoom: <WR state={state} p={player} scores={scores} champId={champ?.currentOwner} go={go} lastRefresh={lastRefresh} refresh={refresh} setPlayer={setPlayer} onTeam={setTeamDetail} avatars={avatars} />,
    bracket: <BM state={state} P={P} PN={PN} go={go} eg={eg} setEg={setEg} scores={scores} sl={sl} refresh={refresh} player={player} triggerFlash={triggerFlash} setNotification={setNotification} onTeam={setTeamDetail} />,
    feed: <Feed state={state} go={go} PN={PN} player={player} avatars={avatars} />,
    leaderboard: <LB state={state} me={player} champ={champ} co={co} go={go} onTeam={setTeamDetail} avatars={avatars} />,
    yearbook: <Yearbook state={state} avatars={avatars} />,
    spotlight: <Spotlight state={state} avatars={avatars} go={go} scores={scores} />,
    admin: <Admin state={state} PN={PN} go={go} resetReveals={()=>{setRevealSeen({});saveReveals({});}} resetAvatars={()=>{setAvatars({});saveAvatars({});}} />,
  };

  return (
    <ErrorBoundary>
    <div style={{background:"#0B1120",minHeight:"100vh",color:"#fff",fontFamily:"'Inter',sans-serif",paddingBottom:showNav?"calc(95px + env(safe-area-inset-bottom, 0px))":"0",maxWidth:"100vw",overflowX:"hidden"}}>
      {/* Elimination Obituary */}
      {obituary&&<Obituary player={obituary} state={state} avatars={avatars} onDismiss={()=>setObituary(null)} />}
      {/* Round Recap Stories */}
      {showRecap&&<RoundRecap state={state} avatars={avatars} onDone={()=>{
        const rd=state.currentRound;
        const ns={...recapSeen,[rd]:true};
        setRecapSeen(ns);
        try{localStorage.setItem("mm-recap-seen",JSON.stringify(ns));}catch(e){}
        setShowRecap(false);
      }} />}
      {/* Screen flash on resolve */}
      {flash&&<div style={{position:"fixed",inset:0,background:flash==="steal"?"rgba(255,71,87,0.25)":"rgba(0,212,170,0.2)",zIndex:300,pointerEvents:"none",animation:"flashFade 0.6s ease both"}} />}

      {/* Full-screen steal/cover notification from poll */}
      {notification&&<div onClick={()=>setNotification(null)} style={{position:"fixed",inset:0,zIndex:400,background:notification.type==="steal"?"radial-gradient(circle at 50% 40%, rgba(255,30,50,0.95), rgba(100,0,20,0.98))":"radial-gradient(circle at 50% 40%, rgba(0,212,170,0.95), rgba(0,60,50,0.98))",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",cursor:"pointer",animation:"fadeUp 0.3s ease both"}}>
        <div style={{fontSize:100,marginBottom:16,animation:notification.type==="steal"?"stealBurst 0.6s cubic-bezier(0.34,1.56,0.64,1) both":"stealBurst 0.4s ease both"}}>{notification.type==="steal"?"⚔️":"✅"}</div>
        <div style={{fontSize:42,fontWeight:900,color:"#fff",fontFamily:"'Oswald',sans-serif",letterSpacing:6,textShadow:"0 4px 30px rgba(0,0,0,0.5)",animation:"fadeUp 0.4s ease 0.2s both"}}>{notification.type==="steal"?"STOLEN!":"COVERED"}</div>
        <div style={{fontSize:28,fontWeight:800,color:"rgba(255,255,255,0.95)",marginTop:16,animation:"fadeUp 0.4s ease 0.3s both"}}>{notification.team}</div>
        <div style={{width:60,height:3,background:"rgba(255,255,255,0.3)",borderRadius:2,margin:"16px 0",animation:"fadeUp 0.4s ease 0.35s both"}}/>
        {notification.stolen?
          <div style={{animation:"slideOwner 0.5s ease 0.4s both"}}><span style={{fontSize:18,color:"rgba(255,255,255,0.6)"}}>from </span><span style={{fontSize:22,fontWeight:800,color:"#fff"}}>{notification.from}</span><span style={{fontSize:18,color:"rgba(255,255,255,0.6)"}}> → </span><span style={{fontSize:22,fontWeight:800,color:"#FFD700"}}>{notification.to}</span></div>:
          <div style={{fontSize:18,color:"rgba(255,255,255,0.7)",animation:"fadeUp 0.4s ease 0.4s both"}}>{notification.to} keeps control</div>}
        <div style={{fontSize:11,color:"rgba(255,255,255,0.3)",marginTop:32,letterSpacing:3,animation:"pulse 2s infinite"}}>TAP ANYWHERE</div>
      </div>}
      {/* Score toast */}
      {toast&&<div onClick={()=>{setToast(null);go("bracket");}} style={{position:"fixed",top:16,left:16,right:16,zIndex:250,background:"#131D2F",border:"1px solid #FF6B3560",borderRadius:12,padding:14,display:"flex",alignItems:"center",justifyContent:"space-between",cursor:"pointer",animation:"fadeUp 0.3s ease both",boxShadow:"0 8px 30px rgba(0,0,0,0.5)"}}>
        <div style={{display:"flex",alignItems:"center",gap:10}}>
          <Logo name={toast.team.name} size={28} />
          <div>
            <div style={{fontSize:17,fontWeight:700,color:"#fff"}}>🏀 {toast.game.away?.abbr} {toast.game.away?.score} — {toast.game.home?.score} {toast.game.home?.abbr} FINAL</div>
            <div style={{fontSize:13,color:"#FF6B35",marginTop:2}}>Your team {toast.team.name} just finished — tap to resolve →</div>
          </div>
        </div>
        <button onClick={e=>{e.stopPropagation();setToast(null);}} style={{background:"none",border:"none",color:"#7B8CA8",fontSize:21,cursor:"pointer"}}>✕</button>
      </div>}
      {/* Team detail drawer */}
      {teamDetail&&<TeamDetail team={teamDetail} state={state} onClose={()=>setTeamDetail(null)} />}
      <div style={{
        opacity:trans==="out"?0:1,
        transform:trans==="out"?"scale(0.97) translateY(12px)":trans==="in"?"none":"none",
        filter:trans==="out"?"blur(4px)":"none",
        transition:trans==="out"?"all 0.2s cubic-bezier(0.4,0,1,1)":"all 0.3s cubic-bezier(0,0,0.2,1)",
      }}>{content[view]}</div>
      {showNav && <Nav view={view} go={go} hasLive={hasLive} playerColor={player?.color} />}
      <style>{`@keyframes slideIn{from{opacity:0;transform:translateX(40px)}to{opacity:1;transform:translateX(0)}}@keyframes fadeUp{from{opacity:0;transform:translateY(20px)}to{opacity:1;transform:translateY(0)}}@keyframes pulse{0%,100%{opacity:1}50%{opacity:0.5}}@keyframes shake{0%,100%{transform:translateX(0)}25%{transform:translateX(-4px)}75%{transform:translateX(4px)}}@keyframes confetti{0%{transform:translateY(0) rotate(0deg);opacity:1}100%{transform:translateY(400px) rotate(720deg);opacity:0}}@keyframes flashFade{0%{opacity:1}100%{opacity:0}}@keyframes cardFlipIn{0%{transform:rotateY(90deg);opacity:0}50%{opacity:1}100%{transform:rotateY(0deg);opacity:1}}@keyframes cardSwapIn{from{opacity:0;transform:scale(0.9) translateX(30px)}to{opacity:1;transform:scale(1) translateX(0)}}@keyframes scorePulse{0%,100%{transform:scale(1)}50%{transform:scale(1.08)}}@keyframes glowPulse{0%,100%{box-shadow:0 0 8px rgba(255,71,87,0.2)}50%{box-shadow:0 0 20px rgba(255,71,87,0.5)}}@keyframes stealBurst{0%{transform:scale(0.5) rotate(-10deg);opacity:0}50%{transform:scale(1.2) rotate(5deg);opacity:1}100%{transform:scale(1) rotate(0deg);opacity:1}}@keyframes slideOwner{0%{transform:translateX(-30px);opacity:0}100%{transform:translateX(0);opacity:1}}@keyframes trophySpin{0%{transform:rotateY(0)}100%{transform:rotateY(360deg)}}@keyframes goldGlow{0%,100%{box-shadow:0 0 20px rgba(255,215,0,0.3)}50%{box-shadow:0 0 40px rgba(255,215,0,0.6)}}`}</style>
    </div>
    </ErrorBoundary>
  );
}

// --- CHAMPIONSHIP SPOTLIGHT MODE ---
function Spotlight({ state, avatars, go, scores }) {
  const alive = state.teams.filter(t => t.alive);
  const owners = [...new Set(alive.map(t => t.currentOwner))];
  const RD = ["Round 1","Round 2","Sweet 16","Elite 8","Final Four","Championship"][state.currentRound] || "";
  const isFinalFour = alive.length <= 4;
  const isChampionship = alive.length <= 2;
  const allGames = state.games.filter(g => g.completed && g.transferInfo);
  const totalSteals = allGames.filter(g => g.transferInfo.stolen).length;
  return (
    <div style={{padding:20,maxWidth:600,margin:"0 auto",textAlign:"center"}}>
      <div style={{background:isFinalFour?"linear-gradient(135deg, #2a1a0e, #1a1a3e, #0a2a1a)":"linear-gradient(135deg, #1a1a3e, #0B1120)",borderRadius:16,padding:"28px 20px",marginBottom:20,border:"1px solid #FFD70030",boxShadow:isFinalFour?"0 0 60px rgba(255,215,0,0.15)":"0 0 30px rgba(255,215,0,0.1)"}}>
        <div style={{fontSize:14,color:"#FFD700",letterSpacing:6,fontWeight:700,marginBottom:4,animation:"pulse 2s infinite"}}>MARCH MAYHEM</div>
        <div style={{fontSize:isFinalFour?48:36,fontWeight:900,fontFamily:"'Oswald',sans-serif",color:"#fff",letterSpacing:3,textShadow:isFinalFour?"0 0 30px rgba(255,215,0,0.3)":"none"}}>{RD.toUpperCase()}</div>
        <div style={{fontSize:16,color:"#7B8CA8",marginTop:6}}>{alive.length} teams remain {"\u2022"} {totalSteals} steals so far</div>
        {isChampionship&&<div style={{fontSize:20,color:"#FFD700",fontWeight:800,marginTop:12,animation:"goldGlow 3s infinite"}}>THE FINAL GAME</div>}
      </div>
      {(()=>{
        const games = state.games.filter(g => g.round === state.currentRound && !g.completed);
        return games.map(g => {
          const t1 = state.teams.find(t => t.id === g.team1Id);
          const t2 = state.teams.find(t => t.id === g.team2Id);
          if (!t1 || !t2) return null;
          const p1 = state.players[t1.currentOwner];
          const p2 = state.players[t2.currentOwner];
          const sameOwner = p1?.id === p2?.id;
          const sp = Math.abs(g.spread || 0);
          const t1Steals = allGames.filter(x => x.transferInfo.stolen && x.transferInfo.advancer === t1.name).length;
          const t2Steals = allGames.filter(x => x.transferInfo.stolen && x.transferInfo.advancer === t2.name).length;
          const h2h = allGames.filter(x => {const ti = x.transferInfo;return (ti.from === p1?.name && ti.to === p2?.name) || (ti.from === p2?.name && ti.to === p1?.name);});
          return (
            <div key={g.id} style={{background:"linear-gradient(135deg, #1a1a3e, #0B1120)",borderRadius:16,padding:isFinalFour?28:24,marginBottom:16,border:isChampionship?"2px solid #FFD700":"1px solid #FFD70030",boxShadow:isChampionship?"0 0 40px rgba(255,215,0,0.2)":"0 0 20px rgba(255,215,0,0.08)",animation:isChampionship?"goldGlow 3s infinite":"none"}}>
              <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:16}}>
                <div style={{textAlign:"center",flex:1}}>
                  <Logo name={t1.name} size={isFinalFour?64:56} />
                  <div style={{fontSize:isFinalFour?22:20,fontWeight:800,color:"#fff",marginTop:8}}>{t1.name}</div>
                  <div style={{fontSize:13,color:"#7B8CA8"}}>({t1.seed}) seed</div>
                  {t1Steals>0&&<div style={{fontSize:11,color:"#A855F7",marginTop:2}}>{1+t1Steals} owners</div>}
                </div>
                <div style={{textAlign:"center",padding:"0 8px"}}>
                  <div style={{fontSize:32,fontWeight:900,color:"#FFD700",fontFamily:"'Oswald',sans-serif"}}>VS</div>
                  {sp>0&&<div style={{fontSize:14,fontWeight:700,color:"#FF6B35",marginTop:4}}>-{sp}</div>}
                </div>
                <div style={{textAlign:"center",flex:1}}>
                  <Logo name={t2.name} size={isFinalFour?64:56} />
                  <div style={{fontSize:isFinalFour?22:20,fontWeight:800,color:"#fff",marginTop:8}}>{t2.name}</div>
                  <div style={{fontSize:13,color:"#7B8CA8"}}>({t2.seed}) seed</div>
                  {t2Steals>0&&<div style={{fontSize:11,color:"#A855F7",marginTop:2}}>{1+t2Steals} owners</div>}
                </div>
              </div>
              <div style={{display:"flex",justifyContent:"space-around",padding:"14px 0",borderTop:"1px solid #1E3050",borderBottom:"1px solid #1E3050",marginBottom:12}}>
                <div style={{textAlign:"center"}}><PlayerAv player={p1} avatars={avatars} size={44} /><div style={{fontSize:15,fontWeight:700,color:p1?.color||"#fff",marginTop:4}}>{p1?.name}</div></div>
                {sameOwner?<div style={{fontSize:13,color:"#00D4AA",fontWeight:700,alignSelf:"center"}}>SAFE</div>:<div style={{fontSize:24,color:"#7B8CA830",alignSelf:"center"}}>{"\u2694\uFE0F"}</div>}
                <div style={{textAlign:"center"}}><PlayerAv player={p2} avatars={avatars} size={44} /><div style={{fontSize:15,fontWeight:700,color:p2?.color||"#fff",marginTop:4}}>{p2?.name}</div></div>
              </div>
              {h2h.length>0&&!sameOwner&&<div style={{fontSize:13,color:"#FBBF24",textAlign:"center",marginBottom:8,fontWeight:600}}>{h2h.length} steal{h2h.length>1?"s":""} between {p1?.name} and {p2?.name}</div>}
              {!sameOwner&&sp>0&&<div style={{background:"#0B1120",borderRadius:10,padding:12,fontSize:12}}>
                <div style={{display:"flex",justifyContent:"space-between",marginBottom:6}}><span style={{color:"#00D4AA",fontWeight:700}}>If {t1.name} covers:</span><span style={{color:"#fff"}}>{p1?.name} keeps</span></div>
                <div style={{display:"flex",justifyContent:"space-between"}}><span style={{color:"#FF4757",fontWeight:700}}>If spread fails:</span><span style={{color:"#fff"}}>{p2?.name} steals</span></div>
              </div>}
              {g.gameDate&&<div style={{fontSize:12,color:"#7B8CA8",textAlign:"center",marginTop:10}}>{fmtDate(g.gameDate, g.gameTime)}</div>}
            </div>
          );
        });
      })()}
      <div style={{marginTop:16,fontSize:12,color:"#7B8CA8",letterSpacing:2,fontWeight:700}}>OWNERS IN CONTENTION</div>
      <div style={{display:"flex",justifyContent:"center",gap:16,marginTop:12,flexWrap:"wrap"}}>
        {owners.map(oid => {
          const p = state.players[oid];
          const ownedTeams = alive.filter(t => t.currentOwner === oid);
          const oddsVal = calcOdds(state).find(o => o.id === oid);
          return (
            <div key={oid} style={{textAlign:"center",background:"#131D2F",borderRadius:12,padding:"12px 16px",border:"1px solid "+p.color+"30"}}>
              <PlayerAv player={p} avatars={avatars} size={isFinalFour?56:48} />
              <div style={{fontSize:15,fontWeight:700,color:p.color,marginTop:4}}>{p.name}</div>
              <div style={{fontSize:20,fontWeight:900,color:p.color,fontFamily:"'Oswald',sans-serif"}}>{oddsVal?.pct||0}%</div>
              <div style={{fontSize:11,color:"#7B8CA8"}}>{ownedTeams.length} team{ownedTeams.length>1?"s":""}</div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

// --- SEASON RECAP / YEARBOOK ---
function Yearbook({ state, avatars }) {
  const champ = state.teams.find(t => t.alive);
  const winner = champ ? state.players[champ.currentOwner] : null;
  const allGames = state.games.filter(g => g.completed && g.transferInfo);
  const steals = allGames.filter(g => g.transferInfo.stolen);
  const bigUpsets = allGames.filter(g => {
    const t2 = state.teams.find(t => t.id === g.team2Id);
    return g.winnerId === g.team2Id && t2 && t2.seed >= 10;
  });
  
  // Championship team journey
  const champJourney = champ ? allGames.filter(g => g.winnerId === champ.id).map(g => {
    const t1 = state.teams.find(t => t.id === g.team1Id);
    const t2 = state.teams.find(t => t.id === g.team2Id);
    const opp = g.winnerId === g.team1Id ? t2 : t1;
    const ti = g.transferInfo;
    return { round: g.round, opp: opp?.name, margin: g.margin, stolen: ti.stolen, from: ti.from, to: ti.to };
  }) : [];

  // Player stats
  const playerStats = state.players.map(p => {
    const drafted = state.teams.filter(t => t.originalOwner === p.id);
    const stole = state.teams.filter(t => t.currentOwner === p.id && t.originalOwner !== p.id);
    const lost = state.teams.filter(t => t.originalOwner === p.id && t.currentOwner !== p.id);
    const alive = state.teams.filter(t => t.currentOwner === p.id && t.alive);
    const bestSeed = drafted.length > 0 ? Math.min(...drafted.map(t => t.seed)) : 99;
    return { ...p, drafted: drafted.length, stole: stole.length, lost: lost.length, alive: alive.length, bestSeed };
  });

  const RDS = ["Round 1","Round 2","Sweet 16","Elite 8","Final Four","Championship"];

  return (
    <div style={{padding:20,maxWidth:600,margin:"0 auto"}}>
      {/* Trophy header */}
      <div style={{textAlign:"center",marginBottom:24}}>
        <div style={{fontSize:80,animation:"trophySpin 3s ease-in-out infinite"}}>🏆</div>
        <div style={{fontSize:14,color:"#FFD700",letterSpacing:4,fontWeight:700,marginTop:8}}>MARCH MAYHEM 2026</div>
        <div style={{fontSize:36,fontWeight:900,fontFamily:"'Oswald',sans-serif",color:"#fff",letterSpacing:2}}>SEASON RECAP</div>
      </div>

      {/* Champion */}
      {winner && champ && <div style={{background:"linear-gradient(135deg, #2a1a0e, #1a1a3e)",border:"2px solid #FFD700",borderRadius:16,padding:24,marginBottom:20,textAlign:"center",animation:"goldGlow 3s infinite"}}>
        <PlayerAv player={winner} avatars={avatars} size={80} />
        <div style={{fontSize:28,fontWeight:900,color:"#FFD700",fontFamily:"'Oswald',sans-serif",marginTop:12,letterSpacing:3}}>CHAMPION</div>
        <div style={{fontSize:24,fontWeight:800,color:"#fff",marginTop:4}}>{winner.name}</div>
        <div style={{fontSize:16,color:"#7B8CA8",marginTop:4}}>with ({champ.seed}) {champ.name}</div>
      </div>}

      {/* Champion's journey */}
      {champJourney.length > 0 && <div style={{marginBottom:20}}>
        <div style={{fontSize:13,color:"#FFD700",letterSpacing:2,fontWeight:700,marginBottom:10}}>CHAMPIONSHIP JOURNEY</div>
        {champJourney.map((g, i) => (
          <div key={i} style={{display:"flex",alignItems:"center",gap:12,padding:"10px 14px",background:"#131D2F",borderRadius:10,marginBottom:6,borderLeft:"3px solid #FFD700"}}>
            <div style={{fontSize:12,color:"#7B8CA8",fontWeight:700,minWidth:70}}>{RDS[g.round]}</div>
            <div style={{flex:1}}>
              <div style={{fontSize:15,fontWeight:700,color:"#fff"}}>vs {g.opp} <span style={{color:"#7B8CA8",fontSize:13}}>({g.margin} pts)</span></div>
              {g.stolen && <div style={{fontSize:12,color:"#A855F7"}}>Stolen from {g.from}</div>}
            </div>
            <div style={{fontSize:18}}>{g.stolen ? "⚔️" : "✅"}</div>
          </div>
        ))}
      </div>}

      {/* Key stats */}
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:10,marginBottom:20}}>
        <div style={{background:"#131D2F",borderRadius:10,padding:14,textAlign:"center"}}>
          <div style={{fontSize:28,fontWeight:900,color:"#A855F7"}}>{steals.length}</div>
          <div style={{fontSize:11,color:"#7B8CA8",letterSpacing:1}}>TOTAL STEALS</div>
        </div>
        <div style={{background:"#131D2F",borderRadius:10,padding:14,textAlign:"center"}}>
          <div style={{fontSize:28,fontWeight:900,color:"#FF6B35"}}>{bigUpsets.length}</div>
          <div style={{fontSize:11,color:"#7B8CA8",letterSpacing:1}}>BIG UPSETS</div>
        </div>
        <div style={{background:"#131D2F",borderRadius:10,padding:14,textAlign:"center"}}>
          <div style={{fontSize:28,fontWeight:900,color:"#00D4AA"}}>{allGames.length}</div>
          <div style={{fontSize:11,color:"#7B8CA8",letterSpacing:1}}>GAMES</div>
        </div>
      </div>

      {/* Biggest steals */}
      {steals.length > 0 && <div style={{marginBottom:20}}>
        <div style={{fontSize:13,color:"#A855F7",letterSpacing:2,fontWeight:700,marginBottom:10}}>BIGGEST STEALS</div>
        {steals.slice(0, 5).map((g, i) => {
          const ti = g.transferInfo;
          const t1 = state.teams.find(t => t.id === g.team1Id);
          const t2 = state.teams.find(t => t.id === g.team2Id);
          return (
            <div key={i} style={{background:"#131D2F",borderRadius:10,padding:12,marginBottom:6,borderLeft:"3px solid #A855F7"}}>
              <div style={{fontSize:15,fontWeight:700,color:"#fff"}}>{ti.advancer}</div>
              <div style={{fontSize:13,color:"#7B8CA8"}}>{t1?.name} vs {t2?.name} — {ti.to} steals from {ti.from}</div>
            </div>
          );
        })}
      </div>}

      {/* Player final standings */}
      <div style={{fontSize:13,color:"#7B8CA8",letterSpacing:2,fontWeight:700,marginBottom:10}}>FINAL STANDINGS</div>
      {playerStats.sort((a, b) => (a.id === winner?.id ? -1 : b.id === winner?.id ? 1 : b.alive - a.alive || b.stole - a.stole)).map((p, i) => (
        <div key={p.id} style={{display:"flex",alignItems:"center",gap:12,padding:"10px 14px",background:p.id===winner?.id?"#2a1a0e":"#131D2F",borderRadius:10,marginBottom:6,border:p.id===winner?.id?"1px solid #FFD70050":"1px solid #1E3050"}}>
          <div style={{fontSize:16,fontWeight:800,color:"#7B8CA8",width:24,textAlign:"center"}}>{p.id===winner?.id?"👑":i+1}</div>
          <PlayerAv player={p} avatars={avatars} size={36} />
          <div style={{flex:1}}>
            <div style={{fontSize:16,fontWeight:700,color:p.id===winner?.id?"#FFD700":"#fff"}}>{p.name}</div>
            <div style={{fontSize:12,color:"#7B8CA8"}}>{p.stole} steals, {p.lost} lost, best seed: {p.bestSeed}</div>
          </div>
        </div>
      ))}

      <div style={{textAlign:"center",marginTop:24,padding:16,background:"#131D2F",borderRadius:12,fontSize:14,color:"#7B8CA8"}}>
        Built by Zac. Brick by brick. 🧱
      </div>
    </div>
  );
}


// --- ROUND RECAP STORIES ---
function RoundRecap({ state, avatars, onDone }) {
  const [idx, setIdx] = useState(0);
  const [anim, setAnim] = useState(true);

  const resolved = state.games.filter(g => g.completed && g.transferInfo);
  const steals = resolved.filter(g => g.transferInfo.stolen);
  const bigMargin = resolved.length > 0 ? resolved.reduce((a, b) => a.margin > b.margin ? a : b) : null;
  const upsets = resolved.filter(g => {
    const t2 = state.teams.find(t => t.id === g.team2Id);
    return g.winnerId === g.team2Id && t2 && t2.seed >= 10;
  });
  const bigUpset = upsets.length > 0 ? upsets[0] : null;

  const alive = state.teams.filter(t => t.alive);
  const rankings = state.players.map(p => {
    const owned = alive.filter(t => t.currentOwner === p.id);
    const stole = owned.filter(t => t.originalOwner !== p.id);
    const best = owned.length > 0 ? Math.min(...owned.map(t => t.seed)) : 99; return { ...p, alive: owned.length, stolen: stole.length, best };
  }).sort((a, b) => b.alive - a.alive || a.best - b.best || b.stolen - a.stolen);

  // Find biggest mover (most steals) and biggest loser (most teams lost)
  const mover = rankings.reduce((a, b) => a.stolen > b.stolen ? a : b);
  const loserCalc = state.players.map(p => {
    const lost = state.teams.filter(t => t.originalOwner === p.id && t.currentOwner !== p.id && t.alive);
    const dead = state.teams.filter(t => t.originalOwner === p.id && !t.alive);
    return { ...p, lostCount: lost.length + dead.length };
  }).sort((a, b) => b.lostCount - a.lostCount);
  const loser = loserCalc[0];

  const slides = [];
  // 0: Title
  slides.push(
    <div key="title" style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",height:"100%",textAlign:"center",padding:32}}>
      <div style={{fontSize:64,marginBottom:16,animation:"bounce 1s ease infinite"}}>🏀</div>
      <div style={{fontSize:14,color:"#FFD700",letterSpacing:6,fontWeight:700,marginBottom:8}}>MARCH MAYHEM</div>
      <div style={{fontSize:48,fontWeight:900,fontFamily:"'Oswald',sans-serif",color:"#fff",letterSpacing:3,lineHeight:1.1}}>ROUND 1<br/>RECAP</div>
      <div style={{width:60,height:3,background:"linear-gradient(90deg, #FF6B35, #FFD700)",borderRadius:2,margin:"20px 0"}} />
      <div style={{fontSize:18,color:"#7B8CA8"}}>{resolved.length} games. {steals.length} steals. {state.teams.filter(t=>!t.alive).length} eliminated.</div>
      <div style={{fontSize:13,color:"#7B8CA850",marginTop:24,letterSpacing:2}}>TAP TO CONTINUE →</div>
    </div>
  );

  // 1: All steals
  if (steals.length > 0) slides.push(
    <div key="steals" style={{padding:"0 24px",display:"flex",flexDirection:"column",justifyContent:"center",height:"100%"}}>
      <div style={{fontSize:48,marginBottom:8}}>⚔️</div>
      <div style={{fontSize:36,fontWeight:900,fontFamily:"'Oswald',sans-serif",color:"#FF4757",letterSpacing:2,marginBottom:4}}>{steals.length} STEAL{steals.length>1?"S":""}</div>
      <div style={{fontSize:15,color:"#7B8CA8",marginBottom:24}}>Spreads giveth. Spreads taketh away.</div>
      {steals.map((g,i)=>{const ti=g.transferInfo;const sp=Math.abs(g.spread||0);return(
        <div key={i} style={{display:"flex",alignItems:"center",gap:12,padding:"10px 0",borderBottom:"1px solid rgba(255,255,255,0.06)",animation:`fadeUp 0.4s ease ${i*0.15}s both`}}>
          <div style={{fontSize:20,width:32,textAlign:"center"}}>🚨</div>
          <div style={{flex:1}}><div style={{fontSize:17,fontWeight:700,color:"#fff"}}>{ti.advancer}</div><div style={{fontSize:13,color:"#7B8CA8"}}>{ti.from} → <span style={{color:"#FFD700",fontWeight:700}}>{ti.to}</span></div></div>
          <div style={{textAlign:"right"}}><div style={{fontSize:14,fontWeight:700,color:"#FF4757"}}>-{sp}</div><div style={{fontSize:11,color:"#7B8CA8"}}>won by {g.margin}</div></div>
        </div>
      );})}
    </div>
  );

  // 2: Biggest steal spotlight
  if (steals.length > 0) {
    const bs = steals.reduce((a, b) => Math.abs(a.spread||0) - a.margin > Math.abs(b.spread||0) - b.margin ? a : b);
    const bti = bs.transferInfo;
    const bsp = Math.abs(bs.spread||0);
    slides.push(
      <div key="bigsteal" style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",height:"100%",textAlign:"center",padding:32}}>
        <div style={{fontSize:14,color:"#A855F7",letterSpacing:4,fontWeight:700,marginBottom:12}}>STEAL OF THE ROUND</div>
        <div style={{fontSize:80,marginBottom:12,animation:"stealBurst 0.6s cubic-bezier(0.34,1.56,0.64,1) both"}}>⚔️</div>
        <div style={{fontSize:42,fontWeight:900,fontFamily:"'Oswald',sans-serif",color:"#fff",letterSpacing:2}}>{bti.advancer}</div>
        <div style={{width:50,height:2,background:"#A855F7",margin:"16px 0",borderRadius:2}} />
        <div style={{display:"flex",alignItems:"center",gap:16,marginBottom:16}}>
          <div style={{textAlign:"center"}}><PlayerAv player={state.players.find(p=>p.name===bti.from)} avatars={avatars} size={56} /><div style={{fontSize:14,fontWeight:700,marginTop:6,color:"#FF4757"}}>{bti.from}</div></div>
          <div style={{fontSize:28,color:"#7B8CA8"}}>→</div>
          <div style={{textAlign:"center"}}><PlayerAv player={state.players.find(p=>p.name===bti.to)} avatars={avatars} size={56} /><div style={{fontSize:14,fontWeight:700,marginTop:6,color:"#FFD700"}}>{bti.to}</div></div>
        </div>
        <div style={{fontSize:16,color:"#7B8CA8",maxWidth:280,lineHeight:1.5}}>Won by {bs.margin} but the <span style={{color:"#FF4757",fontWeight:700}}>{bsp}-point spread</span> was too much. Stolen.</div>
      </div>
    );
  }

  // 3: Biggest blowout
  if (bigMargin) {
    const bw = state.teams.find(t => t.id === bigMargin.winnerId);
    const bl = state.teams.find(t => t.id === (bigMargin.winnerId === bigMargin.team1Id ? bigMargin.team2Id : bigMargin.team1Id));
    slides.push(
      <div key="blowout" style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",height:"100%",textAlign:"center",padding:32}}>
        <div style={{fontSize:14,color:"#00D4AA",letterSpacing:4,fontWeight:700,marginBottom:12}}>BLOWOUT OF THE ROUND</div>
        <div style={{fontSize:80,marginBottom:12}}>💨</div>
        <div style={{fontSize:42,fontWeight:900,fontFamily:"'Oswald',sans-serif",color:"#fff",letterSpacing:2}}>{bw?.name}</div>
        <div style={{fontSize:22,color:"#7B8CA8",marginTop:8}}>crushed {bl?.name} by</div>
        <div style={{fontSize:72,fontWeight:900,fontFamily:"'Oswald',sans-serif",color:"#00D4AA",marginTop:4,textShadow:"0 0 30px rgba(0,212,170,0.4)"}}>{bigMargin.margin}</div>
      </div>
    );
  }

  // 4: Biggest upset
  if (bigUpset) {
    const uw = state.teams.find(t => t.id === bigUpset.winnerId);
    const ul = state.teams.find(t => t.id === (bigUpset.winnerId === bigUpset.team1Id ? bigUpset.team2Id : bigUpset.team1Id));
    slides.push(
      <div key="upset" style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",height:"100%",textAlign:"center",padding:32}}>
        <div style={{fontSize:14,color:"#FBBF24",letterSpacing:4,fontWeight:700,marginBottom:12}}>UPSET OF THE ROUND</div>
        <div style={{fontSize:80,marginBottom:12}}>🤯</div>
        <div style={{fontSize:36,fontWeight:900,fontFamily:"'Oswald',sans-serif",color:"#FBBF24"}}>({uw?.seed}) {uw?.name}</div>
        <div style={{fontSize:18,color:"#7B8CA8",margin:"8px 0"}}>beat</div>
        <div style={{fontSize:28,fontWeight:800,color:"#FF475780",fontFamily:"'Oswald',sans-serif",textDecoration:"line-through"}}>({ul?.seed}) {ul?.name}</div>
      </div>
    );
  }

  // 5: Power Rankings
  slides.push(
    <div key="standings" style={{padding:"0 20px",display:"flex",flexDirection:"column",justifyContent:"center",height:"100%"}}>
      <div style={{fontSize:14,color:"#FFD700",letterSpacing:4,fontWeight:700,marginBottom:4}}>POWER RANKINGS</div>
      <div style={{fontSize:28,fontWeight:900,fontFamily:"'Oswald',sans-serif",color:"#fff",marginBottom:20}}>AFTER ROUND 1</div>
      {rankings.map((p,i)=>(
        <div key={p.id} style={{display:"flex",alignItems:"center",gap:10,marginBottom:10,animation:`fadeUp 0.3s ease ${i*0.08}s both`}}>
          <div style={{width:24,fontSize:i===0?18:14,textAlign:"center",color:i===0?"#FFD700":"#7B8CA8",fontWeight:800}}>{i===0?"👑":i+1}</div>
          <PlayerAv player={p} avatars={avatars} size={36} />
          <div style={{flex:1}}><div style={{fontSize:16,fontWeight:700,color:"#fff"}}>{p.name}</div></div>
          <div style={{fontSize:22,fontWeight:900,color:p.alive>6?"#00D4AA":p.alive>4?"#FBBF24":"#FF4757",fontFamily:"'Oswald',sans-serif"}}>{p.alive}</div>
          {p.stolen>0&&<div style={{fontSize:11,color:"#A855F7",fontWeight:700,background:"#A855F720",padding:"2px 6px",borderRadius:8}}>⚔️{p.stolen}</div>}
        </div>
      ))}
    </div>
  );

  // 6: Biggest mover + loser
  slides.push(
    <div key="movers" style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",height:"100%",textAlign:"center",padding:32}}>
      <div style={{fontSize:14,color:"#00D4AA",letterSpacing:4,fontWeight:700,marginBottom:20}}>BIGGEST MOVER</div>
      <PlayerAv player={mover} avatars={avatars} size={80} />
      <div style={{fontSize:36,fontWeight:900,fontFamily:"'Oswald',sans-serif",color:"#fff",marginTop:12}}>{mover.name}</div>
      <div style={{display:"flex",gap:24,marginTop:20}}>
        <div style={{textAlign:"center"}}><div style={{fontSize:36,fontWeight:900,color:"#A855F7",fontFamily:"'Oswald',sans-serif"}}>{mover.stolen}</div><div style={{fontSize:11,color:"#7B8CA8",letterSpacing:1}}>STEALS</div></div>
        <div style={{textAlign:"center"}}><div style={{fontSize:36,fontWeight:900,color:"#00D4AA",fontFamily:"'Oswald',sans-serif"}}>{mover.alive}</div><div style={{fontSize:11,color:"#7B8CA8",letterSpacing:1}}>ALIVE</div></div>
      </div>
      {loser&&<div style={{marginTop:28,padding:"12px 20px",background:"#FF475720",borderRadius:10,border:"1px solid #FF475740"}}>
        <div style={{fontSize:11,color:"#FF4757",letterSpacing:2,fontWeight:700,marginBottom:4}}>TOUGHEST ROUND</div>
        <div style={{display:"flex",alignItems:"center",gap:8,justifyContent:"center"}}>
          <PlayerAv player={loser} avatars={avatars} size={28} />
          <span style={{fontSize:16,fontWeight:700,color:"#fff"}}>{loser.name}</span>
          <span style={{fontSize:14,color:"#FF4757",fontWeight:700}}>lost {loser.lostCount}</span>
        </div>
      </div>}
    </div>
  );

  // 7: CTA with dynamic narrative
  const nextRd = ["Round 2","Sweet 16","Elite 8","Final Four","Championship",""][Math.min(state.currentRound+1,5)];
  const leader = rankings[0];
  const trailer = rankings[rankings.length - 1];
  const leaderStealNames = state.teams.filter(t=>t.alive&&t.currentOwner===leader.id&&t.originalOwner!==leader.id).map(t=>t.name);
  const trailerBestSeed = Math.min(...state.teams.filter(t=>t.alive&&t.currentOwner===trailer.id).map(t=>t.seed),99);
  const trailerBestTeam = state.teams.find(t=>t.alive&&t.currentOwner===trailer.id&&t.seed===trailerBestSeed);
  let narrative = "";
  if (leader.alive >= trailer.alive * 2) {
    narrative = leader.name + " is running away with it \u2014 " + leader.alive + " teams alive" + (leader.stolen > 0 ? " and " + leader.stolen + " stolen" : "") + ". " + (leaderStealNames.length > 0 ? leaderStealNames.join(", ") + " \u2014 none of those were drafted. All taken by force. " : "") + "Meanwhile " + trailer.name + " is clinging to life with just " + trailer.alive + " team" + (trailer.alive !== 1 ? "s" : "") + "." + (trailerBestTeam ? " But " + trailerBestTeam.name + " is still dancing \u2014 and in March, thats all you need." : "");
  } else if (leader.alive - trailer.alive <= 1) {
    narrative = "This thing is WIDE open. " + leader.name + " leads with " + leader.alive + " but " + trailer.name + " is right there with " + trailer.alive + ". One steal changes everything. One upset flips the whole board.";
  } else {
    narrative = leader.name + " sits on top with " + leader.alive + " teams" + (leader.stolen > 0 ? " \u2014 " + leader.stolen + " of them stolen" : "") + ". ";
    if (trailer.alive <= 3) {
      narrative += trailer.name + " is on the ropes with " + trailer.alive + " team" + (trailer.alive !== 1 ? "s" : "") + " left. ";
      narrative += trailerBestTeam ? "But (" + trailerBestTeam.seed + ") " + trailerBestTeam.name + " is still alive. Cinderella story incoming? Spreads dont care about your record \u2014 they care about your heart." : "The comeback starts now. Or it doesnt.";
    } else {
      narrative += "The pack is tight. " + rankings.filter(p=>p.alive>=leader.alive-2).length + " players within striking distance. This is anybodys tournament.";
    }
  }
  slides.push(
    <div key="cta" style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",height:"100%",textAlign:"center",padding:24}}>
      <div style={{fontSize:64,marginBottom:12}}>🔥</div>
      <div style={{fontSize:14,color:"#FFD700",letterSpacing:4,fontWeight:700,marginBottom:8}}>{nextRd.toUpperCase()}</div>
      <div style={{fontSize:42,fontWeight:900,fontFamily:"'Oswald',sans-serif",color:"#fff",letterSpacing:2,lineHeight:1.1}}>STARTS<br/>NOW</div>
      <div style={{width:60,height:3,background:"linear-gradient(90deg, #FF6B35, #FFD700)",borderRadius:2,margin:"16px 0"}} />
      <div style={{fontSize:15,color:"#B8C5D4",maxWidth:320,lineHeight:1.6,textAlign:"left",background:"rgba(255,255,255,0.03)",borderRadius:12,padding:"16px 18px",border:"1px solid rgba(255,255,255,0.06)",marginBottom:20}}>
        <span style={{color:"#FFD700",fontWeight:700,fontSize:13,letterSpacing:2,display:"block",marginBottom:6}}>THE STORY SO FAR</span>
        {narrative}
      </div>
      <div style={{fontSize:14,color:"#7B8CA8",maxWidth:260,marginBottom:20}}>{alive.length} teams. 8 owners. Every spread is a chance to steal.</div>
      <button onClick={onDone} style={{background:"#FF6B35",border:"none",borderRadius:12,padding:"16px 48px",color:"#fff",fontSize:18,fontWeight:700,cursor:"pointer",boxShadow:"0 0 30px rgba(255,107,53,0.3)",position:"relative",zIndex:10}}>LET'S GO 🏀</button>
<div style={{marginTop:24,marginBottom:24}}>
        <button onClick={()=>{
          const cv=document.createElement("canvas");cv.width=1080;cv.height=1920;const ctx=cv.getContext("2d");
          const bg=ctx.createLinearGradient(0,0,1080,1920);bg.addColorStop(0,"#0B1120");bg.addColorStop(0.4,"#1a1a3e");bg.addColorStop(1,"#0B1120");ctx.fillStyle=bg;ctx.fillRect(0,0,1080,1920);
          ctx.strokeStyle="#FFD70040";ctx.lineWidth=4;ctx.strokeRect(40,40,1000,1840);
          ctx.textAlign="center";ctx.fillStyle="#FFD700";ctx.font="bold 28px sans-serif";ctx.fillText("MARCH MAYHEM 2026",540,130);
          const gold=ctx.createLinearGradient(340,0,740,0);gold.addColorStop(0,"#FF6B35");gold.addColorStop(1,"#FFD700");ctx.fillStyle=gold;ctx.fillRect(340,150,400,4);
          ctx.fillStyle="#fff";ctx.font="900 72px sans-serif";ctx.fillText("CHAMPION",540,250);
          ctx.font="120px sans-serif";ctx.fillText(String.fromCodePoint(0x1F3C6),540,410);
          if(winner){ctx.fillStyle=winner.color;ctx.font="900 64px sans-serif";ctx.fillText(winner.name.toUpperCase(),540,530);}
          if(champ){ctx.fillStyle="#7B8CA8";ctx.font="bold 32px sans-serif";ctx.fillText("with ("+champ.seed+") "+champ.name,540,590);}
          ctx.fillStyle="#FFD70040";ctx.fillRect(240,650,600,2);
          const st=allGames.filter(g=>g.transferInfo.stolen).length;ctx.fillStyle="#fff";ctx.font="bold 36px sans-serif";ctx.fillText(allGames.length+" Games  |  "+st+" Steals",540,720);
          ctx.fillStyle="#FFD700";ctx.font="bold 24px sans-serif";ctx.fillText("FINAL STANDINGS",540,800);
          playerStats.sort((a,b)=>(a.id===winner?.id?-1:b.id===winner?.id?1:b.alive-a.alive)).forEach((p,i)=>{
            const y=860+i*60;ctx.textAlign="left";ctx.fillStyle=i===0?"#FFD700":"#B8C5D4";ctx.font=i===0?"bold 32px sans-serif":"bold 26px sans-serif";
            ctx.fillText((i===0?String.fromCodePoint(0x1F451)+" ":"   "+(i+1)+". ")+p.name,200,y);ctx.textAlign="right";ctx.fillStyle=p.alive>0?"#00D4AA":"#FF4757";ctx.font="bold 26px sans-serif";ctx.fillText(p.alive+" alive"+(p.stole>0?" | "+p.stole+" stolen":""),880,y);
          });
          ctx.textAlign="center";ctx.fillStyle="#7B8CA850";ctx.font="bold 18px sans-serif";ctx.fillText("marchmayhem.netlify.app",540,1400);ctx.fillText("BUILT BY ZAC",540,1440);
          const a=document.createElement("a");a.download="march-mayhem-champion-2026.png";a.href=cv.toDataURL("image/png");a.click();
        }} style={{...B("#FFD700","#0B1120"),width:"100%",fontSize:18,fontWeight:800,padding:"16px",borderRadius:12,letterSpacing:1}}>
          {String.fromCodePoint(0x1F4F8)} SAVE CHAMPION GRAPHIC
        </button>
        <div style={{fontSize:12,color:"#7B8CA8",textAlign:"center",marginTop:6}}>Downloads a shareable 1080x1920 image</div>
      </div>
      <div style={{marginTop:16,fontSize:11,color:"#7B8CA850",letterSpacing:3}}>BUILT BY ZAC</div>
    </div>
  );
}


// --- ELIMINATION OBITUARY ---
function Obituary({ player, state, avatars, onDismiss }) {
  const drafted = state.teams.filter(t => t.originalOwner === player.id);
  const deadTeams = drafted.filter(t => !t.alive);
  const stolenFrom = state.teams.filter(t => t.originalOwner === player.id && t.currentOwner !== player.id && t.alive);
  const bestSeed = Math.min(...drafted.map(t => t.seed));
  const bestTeam = drafted.find(t => t.seed === bestSeed);
  const resolved = state.games.filter(g => g.completed && g.transferInfo);
  
  // Find the kill shot — the game that eliminated their last team
  const lastAlive = drafted.filter(t => t.alive).length === 0;
  const killShot = resolved.filter(g => {
    const loserId = g.winnerId === g.team1Id ? g.team2Id : g.team1Id;
    return drafted.some(t => t.id === loserId);
  }).pop();
  const killTeam = killShot ? state.teams.find(t => t.id === (killShot.winnerId === killShot.team1Id ? killShot.team2Id : killShot.team1Id)) : null;
  
  // Peak alive count (they started with 8)
  const peakAlive = 8;
  
  // How many rounds they survived
  const maxRound = Math.max(...deadTeams.map(t => t.eliminatedRound || 0), 0);
  const RDS = ["Round 1","Round 2","Sweet 16","Elite 8","Final Four","Championship"];
  
  // Cause of death
  let causeOfDeath = "Spread violence";
  if (stolenFrom.length >= 3) causeOfDeath = "Grand larceny (" + stolenFrom.length + " teams stolen)";
  else if (stolenFrom.length > 0) causeOfDeath = "Robbery — lost " + stolenFrom.map(t => t.name).join(", ");
  else if (deadTeams.every(t => t.seed >= 10)) causeOfDeath = "Never had a chance (all double-digit seeds)";
  else causeOfDeath = "Death by chalk — the spreads showed no mercy";

  return (
    <div onClick={onDismiss} style={{position:"fixed",inset:0,zIndex:450,background:"radial-gradient(circle at 50% 30%, #1a0a0a 0%, #000 70%)",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",cursor:"pointer",animation:"fadeUp 0.5s ease both",fontFamily:"'Inter',sans-serif",color:"#fff",padding:24,textAlign:"center",overflowY:"auto"}}>
      {/* Gravestone */}
      <div style={{fontSize:100,marginBottom:8,animation:"shake 0.5s ease"}}>💀</div>
      <div style={{fontSize:14,color:"#FF4757",letterSpacing:6,fontWeight:700,marginBottom:4}}>REST IN PEACE</div>
      <div style={{width:200,height:2,background:"#FF475740",borderRadius:2,margin:"8px 0 16px"}} />
      
      <PlayerAv player={player} avatars={avatars} size={72} />
      <div style={{fontSize:36,fontWeight:900,fontFamily:"'Oswald',sans-serif",color:"#fff",letterSpacing:3,marginTop:12}}>{player.name}</div>
      <div style={{fontSize:16,color:"#7B8CA8",marginTop:4}}>2026 March Mayhem</div>
      
      {/* Gravestone details */}
      <div style={{background:"rgba(255,255,255,0.03)",borderRadius:14,padding:"20px 24px",marginTop:20,maxWidth:340,width:"100%",border:"1px solid #FF475720",textAlign:"left"}}>
        <div style={{display:"flex",justifyContent:"space-between",marginBottom:12,paddingBottom:12,borderBottom:"1px solid rgba(255,255,255,0.06)"}}>
          <div><div style={{fontSize:11,color:"#7B8CA8",letterSpacing:1}}>DRAFTED</div><div style={{fontSize:20,fontWeight:800,color:"#fff"}}>{drafted.length} teams</div></div>
          <div style={{textAlign:"right"}}><div style={{fontSize:11,color:"#7B8CA8",letterSpacing:1}}>SURVIVED</div><div style={{fontSize:20,fontWeight:800,color:"#FF4757"}}>{RDS[maxRound]}</div></div>
        </div>
        <div style={{marginBottom:12}}>
          <div style={{fontSize:11,color:"#7B8CA8",letterSpacing:1,marginBottom:4}}>BEST PICK</div>
          <div style={{fontSize:16,fontWeight:700,color:"#FBBF24"}}>({bestTeam?.seed}) {bestTeam?.name}</div>
        </div>
        {stolenFrom.length > 0 && <div style={{marginBottom:12}}>
          <div style={{fontSize:11,color:"#7B8CA8",letterSpacing:1,marginBottom:4}}>STOLEN FROM THEM</div>
          <div style={{fontSize:14,fontWeight:600,color:"#A855F7"}}>{stolenFrom.map(t => t.name).join(", ")}</div>
        </div>}
        <div style={{marginBottom:12}}>
          <div style={{fontSize:11,color:"#7B8CA8",letterSpacing:1,marginBottom:4}}>CAUSE OF DEATH</div>
          <div style={{fontSize:14,fontWeight:600,color:"#FF4757"}}>{causeOfDeath}</div>
        </div>
        {killTeam && <div>
          <div style={{fontSize:11,color:"#7B8CA8",letterSpacing:1,marginBottom:4}}>KILL SHOT</div>
          <div style={{fontSize:14,fontWeight:600,color:"#fff"}}>{killTeam.name} eliminated in {RDS[killTeam.eliminatedRound||0]}</div>
        </div>}
      </div>

      {/* Tombstone footer */}
      <div style={{marginTop:24,fontSize:14,color:"#7B8CA860",fontStyle:"italic",maxWidth:280}}>
        {stolenFrom.length >= 2 
          ? '"They didnt just lose. They got robbed."'
          : drafted.every(t => !t.alive) 
            ? '"8 teams drafted. 0 survived. Thats March."'
            : '"Gone but not forgotten. See you next year."'}
      </div>
      <div style={{fontSize:11,color:"#7B8CA830",marginTop:20,letterSpacing:3}}>TAP TO DISMISS</div>
    </div>
  );
}

// --- BOTTOM NAV ---
function Nav({ view, go, hasLive, playerColor }) {
  const items = [
    { id: "select", icon: "👤", label: "Players" },
    { id: "warRoom", icon: "⚔️", label: "War Room" },
    { id: "bracket", icon: "📊", label: "Games" },
    { id: "feed", icon: "📢", label: "Feed" },
    { id: "leaderboard", icon: "🏆", label: "Standings" },
  ];
  return (
    <div style={{position:"fixed",bottom:0,left:0,right:0,background:"#0D1520",borderTop:`1px solid ${playerColor?playerColor+"40":"#1E3050"}`,display:"flex",justifyContent:"space-around",padding:"8px 0 calc(12px + env(safe-area-inset-bottom, 0px))",zIndex:100,backdropFilter:"blur(10px)"}}>
      {items.map(it=>{
        const active = view===it.id || (it.id==="select"&&view==="admin");
        return <button key={it.id} onClick={()=>go(it.id)} style={{background:"none",border:"none",cursor:"pointer",display:"flex",flexDirection:"column",alignItems:"center",gap:2,padding:"4px 12px",position:"relative",transition:"transform 0.15s ease",transform:active?"scale(1)":"scale(0.95)"}}>
          <span style={{fontSize:26,filter:active?"none":"grayscale(0.5) opacity(0.6)"}}>{it.icon}</span>
          <span style={{fontSize:12,fontWeight:600,color:active?(playerColor||"#FF6B35"):"#7B8CA8",letterSpacing:0.5,transition:"color 0.2s"}}>{it.label}</span>
          {active&&<div style={{position:"absolute",bottom:-2,width:20,height:3,borderRadius:2,background:playerColor||"#FF6B35",boxShadow:"0 0 8px "+(playerColor||"#FF6B35")+"80",transition:"all 0.3s ease"}} />}
          {it.id==="bracket"&&hasLive&&<div style={{position:"absolute",top:2,right:6,width:8,height:8,borderRadius:"50%",background:"#FF4757",animation:"pulse 1.5s infinite"}} />}
          {it.id==="warRoom"&&hasLive&&<div style={{position:"absolute",top:2,right:8,width:8,height:8,borderRadius:"50%",background:"#FF4757",animation:"pulse 1.5s infinite"}} />}
        </button>;
      })}
    </div>
  );
}

// --- SPLASH ---
function Splash({ go }) {
  const [show, setShow] = useState(false);
  useEffect(()=>{setTimeout(()=>setShow(true),100);},[]);
  return (
    <div style={{minHeight:"100vh",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:20,textAlign:"center",background:"radial-gradient(ellipse at 50% 30%, #2a1a0e 0%, #1a1a3e 40%, #0B1120 80%)"}}>
      <div style={{opacity:show?1:0,transform:show?"scale(1)":"scale(0.85)",transition:"all 0.8s cubic-bezier(0.34, 1.56, 0.64, 1)"}}>
        <img src={MM_LOGO} alt="March Mayhem" style={{width:"100%",maxWidth:420,marginBottom:8,borderRadius:12}} />
      </div>
      <p style={{color:"#7B8CA8",fontSize:16,margin:"0 0 32px",maxWidth:300,opacity:show?1:0,transition:"opacity 0.5s ease 0.4s"}}>8 players. 8 teams each. ESPN spreads decide transfers. Last owner standing wins.</p>
      <button onClick={()=>go("select")} style={{...B("#FF6B35","#fff"),padding:"16px 48px",fontSize:24,borderRadius:12,boxShadow:"0 0 30px rgba(255,107,53,0.3)",opacity:show?1:0,transform:show?"translateY(0)":"translateY(20px)",transition:"all 0.5s ease 0.5s"}}>TAP IN 🏀</button>
      <div style={{marginTop:48,opacity:show?0.7:0,transition:"opacity 0.5s ease 1s",display:"flex",flexDirection:"column",alignItems:"center",gap:6}}>
        <img src={ZAC_IMG} style={{width:48,height:48,borderRadius:"50%",border:"2px solid #FF6B3540",objectFit:"cover"}} alt="Zac" />
        <div style={{fontSize:13,color:"#7B8CA8",fontWeight:600,letterSpacing:2}}>BUILT BY ZAC</div>
      </div>
    </div>
  );
}

// --- SELECT ---
function Sel({ state, champ, co, pick, go, revealSeen, avatars }) {
  const champOwnerId = champ?.currentOwner;
  const odds = useMemo(() => calcOdds(state), [state]);
  return (
    <div style={{padding:20,maxWidth:500,margin:"0 auto",boxSizing:"border-box",overflowX:"hidden"}}>
      {champ&&<Confetti />}
      {champ&&<CC name={champ.name} owner={co} />}
      <div style={{textAlign:"center",marginBottom:24,marginTop:8}}>
        <div style={{fontSize:46}}>🏀</div>
        <h2 style={{fontSize:32,fontWeight:900,color:"#fff",margin:"8px 0 4px",letterSpacing:2}}>WHO ARE YOU?</h2>
        <p style={{color:"#7B8CA8",fontSize:16}}>Tap your name to enter</p>
      </div>

      {/* Tournament Progress */}
      {state.games.length>0&&<div style={{marginBottom:16}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:6}}>
          <span style={{fontSize:13,fontWeight:700,color:"#FF6B35",letterSpacing:1}}>{RDS[state.currentRound]}</span>
          <span style={{fontSize:13,color:"#7B8CA8"}}>{state.teams.filter(t=>t.alive).length} teams alive</span>
        </div>
        <div style={{display:"flex",gap:2}}>
          {RDS.map((_,i)=>{
            const rGames=state.games.filter(g=>g.round===i);
            const done=rGames.length>0&&rGames.every(g=>g.completed);
            const active=i===state.currentRound;
            const future=i>state.currentRound;
            return <div key={i} style={{flex:1,height:4,borderRadius:2,background:done?"#00D4AA":active?"#FF6B35":future?"#1E3050":"#1E3050",opacity:future?0.3:1,transition:"all 0.3s"}} />;
          })}
        </div>
      </div>}

      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,width:"100%",boxSizing:"border-box"}}>
        {state.players.map((p,i)=>{
          const a=state.teams.filter(t=>t.currentOwner===p.id&&t.alive).length;
          const tot=state.teams.filter(t=>t.currentOwner===p.id).length;
          const ic=co?.id===p.id;
          const nw=!revealSeen?.[p.id];
          const pOdds=odds.find(o=>o.id===p.id);
          const elim=a===0&&state.games.some(g=>g.completed); // only show eliminated after games start
          return <button key={p.id} onClick={()=>pick(p)} style={{background:ic?"#1a1a3e":elim?"#0A0E16":"#131D2F",overflow:"hidden",minWidth:0,border:`2px solid ${ic?"#FFD700":elim?"#FF475730":p.color+"40"}`,borderRadius:12,padding:16,cursor:"pointer",textAlign:"left",borderTop:`3px solid ${ic?"#FFD700":elim?"#FF4757":p.color}`,position:"relative",animation:`fadeUp 0.4s ease ${i*0.05}s both`,opacity:elim?0.6:1}}>
            {nw&&!elim&&<div style={{position:"absolute",top:6,right:6,background:"#FF6B35",borderRadius:6,padding:"2px 6px",fontSize:10,fontWeight:700,color:"#fff",animation:"pulse 1.5s infinite"}}>NEW</div>}
            {elim&&<div style={{position:"absolute",top:6,right:6,background:"#FF4757",borderRadius:6,padding:"2px 6px",fontSize:10,fontWeight:700,color:"#fff"}}>💀 OUT</div>}
            <div style={{display:"flex",alignItems:"center",gap:10}}>
              {avatars?.[p.id]&&avatars[p.id]!=="skip"?
                <img src={avatars[p.id]} style={{width:56,height:56,borderRadius:"50%",objectFit:"cover",border:`2px solid ${p.color}`}} alt={p.name} />:
                <div style={{width:56,height:56,borderRadius:"50%",background:elim?"#FF475715":`${p.color}22`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:24,fontWeight:800,color:elim?"#FF4757":p.color}}>{ic?"👑":elim?"💀":p.name.charAt(0)}</div>}
              <div style={{flex:1}}><div style={{fontWeight:700,color:elim?"#7B8CA8":"#fff",fontSize:20}}>{p.name}</div><div style={{fontSize:14,color:a>0?"#00D4AA":"#FF4757",fontWeight:600}}>{elim?"ELIMINATED":<>{a} alive<span style={{color:"#7B8CA8",fontWeight:400}}> / {tot}</span></>}</div></div>
              <div style={{textAlign:"right"}}><div style={{fontSize:20,fontWeight:900,color:elim?"#FF4757":p.color,fontFamily:"'Oswald',sans-serif"}}>{pOdds?.pct||0}%</div><div style={{fontSize:10,color:"#7B8CA8",letterSpacing:1}}>ODDS</div></div>
            </div>
          </button>;
        })}
      </div>
      <button onClick={()=>go("admin")} style={{...B("transparent","#7B8CA8"),width:"100%",marginTop:16,fontSize:14}}>⚙️ Commissioner Tools</button>
    </div>
  );
}

// --- CONFETTI ---
function Confetti() {
  const colors = ["#FF6B35","#FFD700","#00D4AA","#3B82F6","#A855F7","#F43F5E","#FBBF24"];
  const pieces = useMemo(()=>Array.from({length:40},(_,i)=>({left:`${Math.random()*100}%`,w:8+Math.random()*8,h:8+Math.random()*8,c:colors[i%colors.length],br:Math.random()>0.5?"50%":"2px",dur:2+Math.random()*3,del:Math.random()*2,rot:Math.random()*360})),[]);
  return <div style={{position:"fixed",top:0,left:0,right:0,pointerEvents:"none",zIndex:200,overflow:"hidden",height:"100vh"}}>
    {pieces.map((p,i)=><div key={i} style={{position:"absolute",top:-10,left:p.left,width:p.w,height:p.h,background:p.c,borderRadius:p.br,animation:`confetti ${p.dur}s ease-out ${p.del}s both`,transform:`rotate(${p.rot}deg)`}} />)}
  </div>;
}

// --- REVEAL — Horizontal swipe carousel ---
function Reveal({ state, player, onDone }) {
  const [idx, setIdx] = useState(0);
  const [revealed, setRevealed] = useState({});
  const [showSum, setShowSum] = useState(false);
  const touchRef = useRef(null);
  const pid = player?.id ?? -1;
  const myTeams = useMemo(()=>pid>=0?state.teams.filter(t=>t.originalOwner===pid).sort((a,b)=>a.seed-b.seed):[],[state.teams,pid]);
  if(!player) return <div style={{padding:20,textAlign:"center",color:"#7B8CA8"}}>No player selected</div>;
  const g = grade(myTeams);
  const allRevealed = myTeams.every((_,i)=>revealed[i]);

  const reveal = ()=>{if(!revealed[idx])setRevealed(p=>({...p,[idx]:true}));};
  const goNext = ()=>{if(idx<myTeams.length-1){setIdx(idx+1);}else if(allRevealed)setShowSum(true);};
  const goPrev = ()=>{if(idx>0)setIdx(idx-1);};
  const onTouch=(e)=>{touchRef.current=e.touches[0].clientX;};
  const onSwipe=(e)=>{if(!touchRef.current)return;const d=touchRef.current-e.changedTouches[0].clientX;if(Math.abs(d)>50){if(d>0)goNext();else goPrev();}touchRef.current=null;};

  if (showSum) {
    return (
      <div style={{padding:20,maxWidth:500,margin:"0 auto",boxSizing:"border-box",overflowX:"hidden"}}>
        <div style={{textAlign:"center",marginBottom:20}}>
          <div style={{fontSize:52,marginBottom:8}}>🏀</div>
          <h2 style={{fontSize:28,fontWeight:800,color:player.color,margin:0}}>{player.name.toUpperCase()}'S SQUAD</h2>
          <div style={{display:"inline-flex",alignItems:"center",gap:10,marginTop:16,background:"#131D2F",borderRadius:24,padding:"10px 24px",border:`1px solid ${g.c}40`}}>
            <span style={{fontSize:42,fontWeight:900,color:g.c}}>{g.g}</span>
            <div style={{textAlign:"left"}}><div style={{fontSize:17,fontWeight:700,color:"#fff"}}>{g.d}</div><div style={{fontSize:13,color:"#7B8CA8"}}>Avg seed: {g.avg}</div></div>
          </div>
        </div>
        {myTeams.map((t,i)=>{const h=hype(t.seed);return <div key={t.id} style={{background:h.bg,borderRadius:10,padding:12,marginBottom:6,display:"flex",alignItems:"center",justifyContent:"space-between",borderLeft:`3px solid ${player.color}`,animation:`fadeUp 0.3s ease ${i*0.05}s both`}}>
          <div style={{display:"flex",alignItems:"center",gap:10}}>
            <Logo name={t.name} size={32} />
            <div><div style={{fontWeight:700,fontSize:18,color:"#fff"}}>{t.name}</div><div style={{fontSize:13,color:"#7B8CA8"}}>{t.region} • ({t.seed})</div></div>
          </div>
          <div style={{textAlign:"right"}}><span style={{fontSize:21}}>{h.e}</span><div style={{fontSize:10,color:"#7B8CA8",fontWeight:700,letterSpacing:1}}>{h.t}</div></div>
        </div>;})}
        <div style={{background:"#0B1120",border:"1px solid #1E3050",borderRadius:12,padding:16,margin:"16px 0"}}>
          <div style={{fontSize:14,fontWeight:700,color:"#FF6B35",letterSpacing:2,marginBottom:10}}>HOW MARCH MAYHEM WORKS</div>
          <div style={{display:"flex",flexDirection:"column",gap:12}}>
            <RuleRow icon="📺" text="Every tournament game uses the ESPN closing spread." />
            <RuleRow icon="🏀" text="One team wins, one team is eliminated. Normal bracket." />
            <RuleRow icon="🔄" text="The spread winner takes control of whichever team advances. Win the game but lose the spread? You just lost your team." />
            <RuleRow icon="🤝" text="Tie goes to the underdog. Margin = spread means underdog wins the spread." />
            <RuleRow icon="🏆" text="Whoever controls the national champion at the end wins March Mayhem." />
          </div>
        </div>
        <button onClick={onDone} style={{...B("#FF6B35","#fff"),width:"100%",padding:"16px",fontSize:21,borderRadius:12,boxShadow:"0 0 30px rgba(255,107,53,0.2)"}}>LET'S GO 🔥</button>
      </div>
    );
  }

  const cur = myTeams[idx];
  const h = cur ? hype(cur.seed) : null;
  const isRevealed = revealed[idx];

  return (
    <div style={{minHeight:"100vh",display:"flex",flexDirection:"column",background:"radial-gradient(ellipse at 50% 30%, #1a1a3e 0%, #0B1120 60%)",overflow:"hidden"}}
      onTouchStart={onTouch} onTouchEnd={onSwipe}>
      {/* Header */}
      <div style={{textAlign:"center",padding:"24px 20px 0"}}>
        <div style={{fontSize:14,color:player.color,fontWeight:700,letterSpacing:3}}>MEET YOUR SQUAD</div>
        <h2 style={{fontSize:34,fontWeight:900,color:"#fff",margin:"8px 0 0",fontFamily:"'Oswald',sans-serif"}}>{player.name}'s Draft</h2>
        <div style={{display:"flex",justifyContent:"center",gap:6,marginTop:16}}>
          {myTeams.map((_,i)=> <div key={i} onClick={()=>setIdx(i)} style={{width:32,height:5,borderRadius:3,background:i===idx?player.color:revealed[i]?"#7B8CA8":"#1E3050",transition:"all 0.3s",cursor:"pointer"}} />)}
        </div>
        <div style={{fontSize:16,color:"#7B8CA8",marginTop:8}}>{idx+1} / {myTeams.length}</div>
      </div>

      {/* Card area */}
      <div style={{flex:1,display:"flex",alignItems:"center",justifyContent:"center",padding:"20px",position:"relative"}}>
        {/* Left arrow */}
        {idx>0&&<div onClick={goPrev} style={{position:"absolute",left:8,top:"50%",transform:"translateY(-50%)",fontSize:36,color:"#7B8CA8",cursor:"pointer",zIndex:2,padding:"20px 8px"}}>‹</div>}
        {/* Right arrow */}
        {idx<myTeams.length-1&&<div onClick={goNext} style={{position:"absolute",right:8,top:"50%",transform:"translateY(-50%)",fontSize:36,color:"#7B8CA8",cursor:"pointer",zIndex:2,padding:"20px 8px"}}>›</div>}

        {isRevealed ? (
          <div key={`rev-${idx}`} style={{width:"100%",maxWidth:400,perspective:1000}}>
            <div style={{animation:"cardFlipIn 0.6s ease both",transformStyle:"preserve-3d"}}>
              <div style={{background:`linear-gradient(135deg, ${h.bg}, #131D2F)`,borderRadius:20,padding:28,border:`2px solid ${player.color}40`,boxShadow:`0 20px 60px rgba(0,0,0,0.4), 0 0 30px ${player.color}15`}}>
                <div style={{textAlign:"center",marginBottom:16}}>
                  <Logo name={cur.name} size={80} style={{margin:"0 auto 12px",display:"block"}} />
                  <div style={{fontSize:36,fontWeight:900,color:"#fff",fontFamily:"'Oswald',sans-serif",letterSpacing:1}}>{cur.name}</div>
                  <div style={{fontSize:17,color:"#7B8CA8",marginTop:4}}>{cur.region} Region • ({cur.seed}) seed</div>
                </div>
                <div style={{display:"flex",justifyContent:"center",gap:16,marginBottom:16}}>
                  <div style={{textAlign:"center"}}><div style={{fontSize:36}}>{h.e}</div><div style={{fontSize:12,fontWeight:700,color:player.color,letterSpacing:1}}>{h.t}</div></div>
                </div>
                {TEAM_HYPE[cur.name]&&<div style={{fontSize:17,color:"#B8C5D4",lineHeight:1.7,textAlign:"center",padding:"12px 0",borderTop:"1px solid #1E3050"}}>{TEAM_HYPE[cur.name]}</div>}
              </div>
            </div>
          </div>
        ) : (
          <div key={`mys-${idx}`} onClick={reveal} style={{width:"100%",maxWidth:400,cursor:"pointer",perspective:1000}}>
            <div style={{animation:idx===0?"fadeUp 0.5s ease":"cardSwapIn 0.3s ease",transformStyle:"preserve-3d"}}>
              <div style={{background:"linear-gradient(135deg, #1E3050, #0B1120)",borderRadius:20,padding:48,border:`2px solid ${player.color}20`,textAlign:"center",boxShadow:"0 20px 60px rgba(0,0,0,0.3)",minHeight:280,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center"}}>
                <div style={{fontSize:64,marginBottom:16,animation:"pulse 2s ease infinite"}}>❓</div>
                <div style={{fontSize:24,fontWeight:700,color:"#B8C5D4",letterSpacing:1}}>TAP TO REVEAL</div>
                <div style={{fontSize:17,color:"#7B8CA8",marginTop:8}}>Team #{idx+1} of 8</div>
                <div style={{fontSize:14,color:player.color,marginTop:4,fontWeight:600}}>{h?.t} tier incoming</div>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Bottom controls */}
      <div style={{padding:"0 20px 24px",display:"flex",gap:10}}>
        {!allRevealed ? <>
          <button onClick={()=>{const rv={};myTeams.forEach((_,i)=>rv[i]=true);setRevealed(rv);}} style={{...B("transparent","#7B8CA8","1px solid #2A3A5C"),flex:1,fontSize:16}}>REVEAL ALL</button>
          {isRevealed&&idx<myTeams.length-1?
            <button onClick={goNext} style={{...B("#FF6B35","#fff"),flex:2}}>NEXT →</button>:
            !isRevealed?<button onClick={reveal} style={{...B("#FF6B35","#fff"),flex:2}}>REVEAL</button>:null}
        </> :
          <button onClick={()=>setShowSum(true)} style={{...B("#FF6B35","#fff"),flex:1,fontSize:21,padding:"14px"}}> VIEW FULL SQUAD →</button>
        }
      </div>

      {/* Swipe hint */}
      {idx===0&&!isRevealed&&<div style={{textAlign:"center",paddingBottom:16,fontSize:14,color:"#7B8CA840"}}>← swipe to navigate →</div>}
    </div>
  );
}

// --- AVATAR SETUP ---
function AvatarSetup({ player, onDone }) {
  const [stage, setStage] = useState("ask");
  const fileRef = useRef(null);
  const pName = player?.name || "?";
  const pColor = player?.color || "#7B8CA8";

  const handleFile = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      // Resize to 128px circle
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement("canvas");
        canvas.width = 128; canvas.height = 128;
        const ctx = canvas.getContext("2d");
        const size = Math.min(img.width, img.height);
        const sx = (img.width - size) / 2, sy = (img.height - size) / 2;
        ctx.beginPath(); ctx.arc(64, 64, 64, 0, Math.PI * 2); ctx.clip();
        ctx.drawImage(img, sx, sy, size, size, 0, 0, 128, 128);
        onDone(canvas.toDataURL("image/jpeg", 0.7));
      };
      img.src = ev.target.result;
    };
    reader.readAsDataURL(file);
  };

  return (
    <div style={{minHeight:"100vh",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:20,background:"radial-gradient(ellipse at 50% 30%, #1a1a3e 0%, #0B1120 60%)"}}>
      <div style={{textAlign:"center",maxWidth:400,width:"100%",animation:"fadeUp 0.4s ease both"}}>
        <div style={{width:100,height:100,borderRadius:"50%",background:`${pColor}22`,border:`3px solid ${pColor}`,display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 20px",fontSize:52,fontWeight:900,color:pColor}}>
          {pName.charAt(0)}
        </div>
        <h2 style={{fontSize:32,fontWeight:900,color:"#fff",margin:"0 0 4px",fontFamily:"'Oswald',sans-serif"}}>{pName}</h2>

        {stage === "ask" && <>
          <p style={{color:"#7B8CA8",fontSize:17,margin:"8px 0 28px"}}>Want to add a profile photo?<br/>This is a one-time thing.</p>
          <button onClick={() => fileRef.current?.click()} style={{...B("#FF6B35","#fff"),width:"100%",padding:"16px",fontSize:20,borderRadius:12,marginBottom:12,boxShadow:"0 0 30px rgba(255,107,53,0.2)"}}>📸 Upload Photo</button>
          <input ref={fileRef} type="file" accept="image/*" onChange={handleFile} style={{display:"none"}} />
          <button onClick={() => setStage("confirm_skip")} style={{...B("transparent","#7B8CA8","1px solid #2A3A5C"),width:"100%",fontSize:17}}>No thanks</button>
        </>}

        {stage === "confirm_skip" && <>
          <p style={{color:"#FBBF24",fontSize:18,fontWeight:600,margin:"8px 0 4px"}}>Are you sure?</p>
          <p style={{color:"#7B8CA8",fontSize:16,margin:"0 0 28px"}}>You won't be able to add one later. Your initial will be used instead.</p>
          <div style={{display:"flex",gap:10}}>
            <button onClick={() => setStage("ask")} style={{...B("#1E3050","#B8C5D4"),flex:1,fontSize:17}}>Go Back</button>
            <button onClick={() => onDone("skip")} style={{...B("#FF6B35","#fff"),flex:1,fontSize:17}}>Skip for real</button>
          </div>
        </>}
      </div>
    </div>
  );
}

function RuleRow({ icon, text }) {
  return <div style={{display:"flex",gap:10,alignItems:"flex-start"}}><span style={{fontSize:24,flexShrink:0}}>{icon}</span><span style={{fontSize:17,color:"#B8C5D4",lineHeight:1.5}}>{text}</span></div>;
}

// --- WAR ROOM ---
function WR({ state, p, scores, go, lastRefresh, refresh, setPlayer, onTeam, avatars, champId }) {
  if(!p) return <div style={{padding:20,textAlign:"center",color:"#7B8CA8"}}>Select a player first<br/><button onClick={()=>go("select")} style={{...B("#FF6B35","#fff"),marginTop:12}}>Go Back</button></div>;

  // Swipe between players
  const pIdx = state.players.findIndex(pl => pl.id === p.id);
  const prevPlayer = state.players[(pIdx - 1 + state.players.length) % state.players.length];
  const nextPlayer = state.players[(pIdx + 1) % state.players.length];

  const my=state.teams.filter(t=>t.currentOwner===p.id);
  const alive=my.filter(t=>t.alive).sort((a,b)=>a.seed-b.seed), dead=my.filter(t=>!t.alive);
  const stolen=my.filter(t=>t.originalOwner!==p.id);
  const lost=state.teams.filter(t=>t.originalOwner===p.id&&t.currentOwner!==p.id);
  const odds = useMemo(() => calcOdds(state), [state]);
  const myOdds = odds.find(o => o.id === p.id);
  const badges = useMemo(() => calcAchievements(state, p.id), [state, p.id]);
  const streak = useMemo(() => calcStreak(state, p.id), [state, p.id]);

  // Refresh timestamp
  const ago = lastRefresh ? Math.round((Date.now() - lastRefresh) / 1000) : null;
  const [tick, setTick] = useState(0);
  useEffect(() => { const i = setInterval(() => setTick(t => t + 1), 5000); return () => clearInterval(i); }, []);

  return (
    <div style={{padding:20,maxWidth:600,margin:"0 auto",boxSizing:"border-box",overflowX:"hidden"}}>
      {/* Player header */}
      <div style={{display:"flex",alignItems:"center",gap:16,marginBottom:16}}>
        <PlayerAv player={p} avatars={avatars} size={80} isChamp={p.id===champId} />
        <div style={{flex:1}}>
          <div style={{fontSize:28,fontWeight:900,color:"#fff",fontFamily:"'Oswald',sans-serif"}}>{p.name}</div>
          <div style={{fontSize:14,color:"#7B8CA8"}}>{RDS[state.currentRound]} • {alive.length} alive</div>
        </div>
        <div style={{display:"flex",gap:6}}>
          <button onClick={()=>setPlayer(prevPlayer)} style={{background:"none",border:"1px solid #1E3050",borderRadius:8,width:36,height:36,cursor:"pointer",color:"#7B8CA8",fontSize:18,display:"flex",alignItems:"center",justifyContent:"center"}}>←</button>
          <button onClick={()=>setPlayer(nextPlayer)} style={{background:"none",border:"1px solid #1E3050",borderRadius:8,width:36,height:36,cursor:"pointer",color:"#7B8CA8",fontSize:18,display:"flex",alignItems:"center",justifyContent:"center"}}>→</button>
        </div>
      </div>

      <div style={{background:"#131D2F",borderRadius:12,padding:20,marginBottom:16,borderTop:`3px solid ${p.color}`}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
          <div style={{display:"flex",gap:8,alignItems:"center"}}>
            <div style={{background:"#0B1120",borderRadius:10,padding:"6px 12px",border:`1px solid ${p.color}40`,textAlign:"center"}}>
              <div style={{fontSize:26,fontWeight:900,color:p.color,fontFamily:"'Oswald',sans-serif"}}>{myOdds?.pct||0}%</div>
              <div style={{fontSize:10,color:"#7B8CA8",fontWeight:700,letterSpacing:1}}>WIN ODDS</div>
            </div>
          </div>
        </div>
        <div style={{display:"flex",gap:8,marginTop:16}}>
          <SB v={alive.length} l="ALIVE" c="#00D4AA" /><SB v={stolen.length} l="STOLEN" c="#A855F7" /><SB v={lost.length} l="LOST" c="#FF6B35" /><SB v={dead.length} l="DEAD" c="#FF4757" />
        </div>
        {/* Refresh bar */}
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginTop:12,paddingTop:8,borderTop:"1px solid #1E3050"}}>
          <span style={{fontSize:12,color:"#7B8CA8"}}>{ago!=null?`Updated ${ago<60?`${ago}s`:`${Math.floor(ago/60)}m`} ago`:"Not refreshed yet"}</span>
          <button onClick={()=>refresh()} style={{background:"none",border:"1px solid #1E3050",borderRadius:8,padding:"8px 14px",color:"#00D4AA",cursor:"pointer",fontSize:13,fontWeight:700}}>↻ Refresh</button>
        </div>
      </div>

      {/* Streak + Achievements */}
      {(streak>0||badges.length>0)&&<div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:16}}>
        {streak>=2&&<div style={{background:"#FF6B3520",borderRadius:20,padding:"4px 12px",display:"flex",alignItems:"center",gap:4,border:"1px solid #FF6B3540"}}><span style={{fontSize:18}}>🔥</span><span style={{fontSize:14,fontWeight:700,color:"#FF6B35"}}>{streak} streak</span></div>}
        {badges.map((b,i)=><div key={i} style={{background:"#131D2F",borderRadius:20,padding:"4px 12px",display:"flex",alignItems:"center",gap:4,border:"1px solid #1E3050"}}><span style={{fontSize:18}}>{b.icon}</span><span style={{fontSize:13,fontWeight:600,color:"#B8C5D4"}}>{b.name}</span></div>)}
      </div>}

      {/* GHOST MODE */}
      {alive.length===0&&state.games.some(g=>g.completed)&&<div style={{animation:"fadeUp 0.4s ease both"}}>
        <div style={{textAlign:"center",padding:"20px 20px 16px",background:"linear-gradient(135deg, #1a0a0a, #0B1120)",borderRadius:14,border:"1px solid #FF475730",marginBottom:16}}>
          <div style={{fontSize:48,marginBottom:8}}>{String.fromCodePoint(0x1F47B)}</div>
          <div style={{fontSize:22,fontWeight:900,color:"#FF4757",letterSpacing:2,fontFamily:"'Oswald',sans-serif"}}>GHOST MODE</div>
          <div style={{fontSize:14,color:"#7B8CA8",marginTop:4}}>Your teams are gone but the show goes on.</div>
        </div>
        {(()=>{
          const allLive=state.games.filter(g=>!g.completed&&g.team1Id!=null&&g.team2Id!=null).filter(g=>{
            const t1x=state.teams.find(t=>t.id===g.team1Id),t2x=state.teams.find(t=>t.id===g.team2Id);
            return scores.some(ls=>isLive(ls.status)&&t1x&&t2x&&ls.teams.some(lt=>fz(t1x,lt.name,lt.abbr))&&ls.teams.some(lt=>fz(t2x,lt.name,lt.abbr)));
          });
          if(allLive.length===0)return null;
          return <div style={{marginBottom:16}}>
            <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:10}}>
              <div style={{width:8,height:8,borderRadius:"50%",background:"#FF4757",animation:"pulse 1.5s infinite"}} />
              <span style={{fontSize:12,fontWeight:700,color:"#FF4757",letterSpacing:2}}>LIVE NOW</span>
            </div>
            {allLive.map(g=><LiveCard key={g.id} game={g} state={state} scores={scores} onTeam={onTeam} myPlayerId={p.id} />)}
          </div>;
        })()}
        {(()=>{
          const upcoming=state.games.filter(g=>!g.completed&&g.team1Id!=null&&g.team2Id!=null).slice(0,4);
          if(upcoming.length===0)return null;
          return <div style={{marginBottom:16}}>
            <Sec text="UPCOMING GAMES" />
            {upcoming.map(g=>{
              const t1=state.teams.find(t=>t.id===g.team1Id),t2=state.teams.find(t=>t.id===g.team2Id);
              if(!t1||!t2)return null;
              const o1=state.players[t1.currentOwner],o2=state.players[t2.currentOwner];
              return <div key={g.id} style={{background:"#131D2F",borderRadius:10,padding:12,marginBottom:8,border:"1px solid #1E3050"}}>
                <div style={{display:"flex",alignItems:"center",justifyContent:"space-between"}}>
                  <div style={{display:"flex",alignItems:"center",gap:8}}><Logo name={t1.name} size={28}/><div><div style={{fontSize:15,fontWeight:700,color:"#fff"}}>{t1.name}</div><div style={{fontSize:11,color:o1?.color}}>{o1?.name}</div></div></div>
                  <div style={{fontSize:14,fontWeight:700,color:"#FF6B35"}}>-{Math.abs(g.spread||0)}</div>
                  <div style={{display:"flex",alignItems:"center",gap:8}}><div style={{textAlign:"right"}}><div style={{fontSize:15,fontWeight:700,color:"#fff"}}>{t2.name}</div><div style={{fontSize:11,color:o2?.color}}>{o2?.name}</div></div><Logo name={t2.name} size={28}/></div>
                </div>
                {g.gameDate&&<div style={{fontSize:11,color:"#7B8CA8",marginTop:6,textAlign:"center"}}>{fmtDate(g.gameDate,g.gameTime)}</div>}
              </div>;
            })}
          </div>;
        })()}
        <Sec text="YOUR FINAL RECORD" />
        <div style={{background:"#131D2F",borderRadius:10,padding:16,marginBottom:16,border:"1px solid #FF475720"}}>
          <div style={{display:"flex",justifyContent:"space-around",marginBottom:12}}>
            <div style={{textAlign:"center"}}><div style={{fontSize:22,fontWeight:900,color:"#FF4757",fontFamily:"'Oswald',sans-serif"}}>{state.teams.filter(t=>t.originalOwner===p.id&&!t.alive).length}</div><div style={{fontSize:10,color:"#7B8CA8"}}>ELIMINATED</div></div>
            <div style={{textAlign:"center"}}><div style={{fontSize:22,fontWeight:900,color:"#A855F7",fontFamily:"'Oswald',sans-serif"}}>{state.teams.filter(t=>t.originalOwner===p.id&&t.currentOwner!==p.id&&t.alive).length}</div><div style={{fontSize:10,color:"#7B8CA8"}}>STOLEN</div></div>
            <div style={{textAlign:"center"}}><div style={{fontSize:22,fontWeight:900,color:"#00D4AA",fontFamily:"'Oswald',sans-serif"}}>{state.games.filter(g=>g.completed&&g.transferInfo&&!g.transferInfo.stolen&&g.transferInfo.to===p.name).length}</div><div style={{fontSize:10,color:"#7B8CA8"}}>COVERS</div></div>
          </div>
          <div style={{fontSize:13,color:"#7B8CA8",textAlign:"center",fontStyle:"italic"}}>{
            state.teams.filter(t=>t.originalOwner===p.id&&t.currentOwner!==p.id&&t.alive).length>=2
              ?"They robbed you. "+state.teams.filter(t=>t.originalOwner===p.id&&t.currentOwner!==p.id&&t.alive).map(t=>t.name).join(", ")+" still alive in someone elses hands."
              :"The spreads came for you. Maybe next year."
          }</div>
        </div>
        <div style={{display:"flex",gap:10}}>
          <button onClick={()=>go("leaderboard")} style={{...B("#1E3050","#B8C5D4"),flex:1,fontSize:15}}>Standings</button>
          <button onClick={()=>go("bracket")} style={{...B("#1E3050","#B8C5D4"),flex:1,fontSize:15}}>Games</button>
        </div>
      </div>}

      {/* Live games for YOUR teams */}
      {alive.length>0&&(()=>{
        const myLive=state.games.filter(g=>!g.completed&&g.team1Id!=null&&g.team2Id!=null).filter(g=>{
          const t1x=state.teams.find(t=>t.id===g.team1Id),t2x=state.teams.find(t=>t.id===g.team2Id);
          const hasMine=(t1x&&t1x.currentOwner===p.id)||(t2x&&t2x.currentOwner===p.id);
          return hasMine&&scores.some(ls=>isLive(ls.status)&&t1x&&t2x&&ls.teams.some(lt=>fz(t1x,lt.name,lt.abbr))&&ls.teams.some(lt=>fz(t2x,lt.name,lt.abbr)));
        });
        if(myLive.length===0)return null;
        return <div style={{marginBottom:16}}>
          <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:10}}>
            <div style={{width:8,height:8,borderRadius:"50%",background:"#FF4757",animation:"pulse 1.5s infinite"}} />
            <span style={{fontSize:12,fontWeight:700,color:"#FF4757",letterSpacing:2}}>YOUR GAMES LIVE</span>
          </div>
          {myLive.map(g=><LiveCard key={g.id} game={g} state={state} scores={scores} onTeam={onTeam} myPlayerId={p.id} />)}
        </div>;
      })()}

      {alive.length>0&&<><Sec text="ACTIVE ROSTER" />{alive.map(t=>{
        const lv=scores.find(ls=>ls.teams.some(lt=>fz(t,lt.name,lt.abbr)));
        const isLv=isLive(lv?.status);
        // Find this team's upcoming/current game
        const game=state.games.find(g=>!g.completed&&(g.team1Id===t.id||g.team2Id===t.id));
        const oppId=game?(game.team1Id===t.id?game.team2Id:game.team1Id):null;
        const opp=oppId!=null?state.teams.find(x=>x.id===oppId):null;
        const isFav=game&&game.team1Id===t.id;
        const oppOwner=opp?state.players[opp.currentOwner]:null;
        return <div key={t.id} onClick={()=>onTeam&&onTeam(t)} style={{background:"#131D2F",borderRadius:10,marginBottom:8,borderLeft:`3px solid ${isLv?"#FF4757":"#00D4AA"}`,overflow:"hidden",cursor:onTeam?"pointer":"default",boxShadow:isLv?"0 0 12px rgba(255,71,87,0.15)":"none"}}>
          <div style={{padding:14,display:"flex",alignItems:"center",justifyContent:"space-between"}}>
            <div style={{display:"flex",alignItems:"center",gap:12}}>
              <Logo name={t.name} size={40} />
              <div>
                <div style={{fontWeight:700,fontSize:18,color:"#fff"}}>{t.name}{t.originalOwner!==t.currentOwner&&<span style={{color:"#A855F7",fontSize:13,marginLeft:6}}>← {state.players[t.originalOwner]?.name}</span>}</div>
                {game&&opp?<div style={{fontSize:13,color:"#7B8CA8"}}>
                  vs <span style={{color:oppOwner?.color||"#fff",fontWeight:600}}>{opp.name}</span>
                  {game.spread!==0?<span style={{color:"#FF6B35",fontWeight:600}}> {isFav?`(-${game.spread})`:`(+${game.spread})`}</span>:<span style={{color:"#7B8CA8"}}> Pick'em</span>}
                  {oppOwner&&oppOwner.id!==p.id&&<span style={{color:oppOwner.color}}> • {oppOwner.name}'s team</span>}
                  {oppOwner&&oppOwner.id===p.id&&<span style={{color:"#FBBF24"}}> • your team 😮‍💨</span>}
                </div>:<div style={{fontSize:13,color:"#7B8CA8"}}>Waiting for next round</div>}
                {game&&game.gameDate&&<div style={{fontSize:12,color:"#7B8CA850"}}>{fmtDate(game.gameDate,game.gameTime)}</div>}
              </div>
            </div>
            <div style={{display:"flex",alignItems:"center",gap:6}}>
              {isLv&&<span style={{fontSize:14,fontWeight:700,color:"#FF4757",background:"#FF475715",padding:"2px 6px",borderRadius:4}}>{lv.away?.abbr} {lv.away?.score}-{lv.home?.score} {lv.home?.abbr}</span>}
              <div style={{fontSize:26}}>{isLv?<span style={{animation:"pulse 1.5s infinite"}}>🔴</span>:"🟢"}</div>
            </div>
          </div>
          {lv&&lv.status==="STATUS_FINAL"&&<div style={{background:"#0B1120",padding:"8px 14px",display:"flex",justifyContent:"space-between",alignItems:"center",borderTop:"1px solid #1E3050"}}>
            <span style={{fontSize:17,fontWeight:700,color:"#fff"}}>{lv.away?.abbr} {lv.away?.score} — {lv.home?.score} {lv.home?.abbr}</span>
            <LBg s={lv.status} d={lv.detail} ck={lv.clock} pr={lv.period} />
          </div>}
        </div>;
      })}</>}
      {/* Recent results */}
      {(()=>{
        const myRes=state.games.filter(g=>g.completed&&g.transferInfo).filter(g=>{
          const t1o=state.teams.find(t=>t.id===g.team1Id);
          const t2o=state.teams.find(t=>t.id===g.team2Id);
          return (t1o&&(t1o.currentOwner===p.id||t1o.originalOwner===p.id))||(t2o&&(t2o.currentOwner===p.id||t2o.originalOwner===p.id));
        }).slice(-5);
        if(myRes.length===0)return null;
        return <div style={{marginBottom:16}}><Sec text="RECENT RESULTS" />{myRes.map(g=><ResolvedCard key={g.id} game={g} state={state} onTeam={onTeam} />)}</div>;
      })()}

      {dead.length>0&&<div style={{marginTop:12}}><Sec text="ELIMINATED (on roster)" />{dead.map(t=><TC key={t.id} t={t} s={state} dim onTeam={onTeam} />)}</div>}
      {lost.length>0&&<div style={{marginTop:12}}><Sec text="LOST TO OTHERS" />{lost.map(t=><div key={t.id} onClick={()=>onTeam&&onTeam(t)} style={{background:"#0D1520",borderRadius:8,padding:10,marginBottom:6,display:"flex",alignItems:"center",justifyContent:"space-between",opacity:0.5,cursor:"pointer"}}><div style={{display:"flex",alignItems:"center",gap:8}}><Logo name={t.name} size={20} style={{opacity:0.5}} /><span style={{fontSize:16,color:"#7B8CA8"}}>({t.seed}) {t.name}</span></div><span style={{fontSize:13,color:state.players[t.currentOwner]?.color,fontWeight:600}}>→ {state.players[t.currentOwner]?.name}</span></div>)}</div>}

      {/* HEAD-TO-HEAD RECORDS */}
      {(()=>{
        const completed=state.games.filter(g=>g.completed&&g.transferInfo);
        if(completed.length===0)return null;
        const h2h={};
        completed.forEach(g=>{
          const t1=state.teams.find(t=>t.id===g.team1Id),t2=state.teams.find(t=>t.id===g.team2Id);
          if(!t1||!t2)return;
          const ti=g.transferInfo;
          const fromPlayer=state.players.find(pl=>pl.name===ti.from);
          const toPlayer=state.players.find(pl=>pl.name===ti.to);
          if(!fromPlayer||!toPlayer||fromPlayer.id===toPlayer.id)return; // same owner, skip
          const winner=ti.stolen?toPlayer:fromPlayer; // spread winner
          const loser=ti.stolen?fromPlayer:toPlayer;
          if(winner.id!==p.id&&loser.id!==p.id)return; // not involving this player
          const oppId=winner.id===p.id?loser.id:winner.id;
          if(!h2h[oppId])h2h[oppId]={wins:0,losses:0,opp:state.players[oppId]};
          if(winner.id===p.id)h2h[oppId].wins++;else h2h[oppId].losses++;
        });
        const records=Object.values(h2h).filter(r=>r.wins+r.losses>0).sort((a,b)=>(b.wins+b.losses)-(a.wins+a.losses));
        if(records.length===0)return null;
        return <div style={{marginTop:12}}>
          <Sec text="⚔️ HEAD-TO-HEAD" />
          <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
            {records.map(r=><div key={r.opp.id} style={{background:"#131D2F",borderRadius:8,padding:"8px 12px",border:`1px solid ${r.wins>r.losses?"#00D4AA40":r.wins<r.losses?"#FF475740":"#1E3050"}`,display:"flex",alignItems:"center",gap:8}}>
              <div style={{width:8,height:8,borderRadius:"50%",background:r.opp.color}} />
              <span style={{fontSize:16,fontWeight:700,color:"#fff"}}>{r.opp.name}</span>
              <span style={{fontSize:16,fontWeight:800,color:r.wins>r.losses?"#00D4AA":r.wins<r.losses?"#FF4757":"#7B8CA8"}}>{r.wins}-{r.losses}</span>
            </div>)}
          </div>
        </div>;
      })()}

      {/* Share War Room */}
      <button onClick={()=>{
        const aliveNames=alive.map(t=>`${t.name} (${t.seed})`).join(", ");
        const txt=`${p.name}'s War Room — ${RDS[state.currentRound]}\n📊 ${alive.length} alive | ${dead.length} dead | ${stolen.length} stolen\n🎯 Win odds: ${myOdds?.pct||0}%\n🏀 Teams: ${aliveNames||"None"}\n\n🏀 MARCH MAYHEM 2026`;
        navigator.clipboard?.writeText(txt);
      }} style={{...B("#1E3050","#7B8CA8"),width:"100%",marginTop:20,fontSize:14}}>📋 Share War Room</button>
    </div>
  );
}

// --- DRAMA FEED ---
function Feed({ state, go, PN, player, avatars }) {
  const [msg, setMsg] = useState("");
  const feed = (state.feed||[]).slice().reverse().slice(0, 100);
  const rd = state.currentRound;
  // Round recap: show if all games in current or previous round are done
  const checkRd = rd;
  const checkGames = state.games.filter(g => g.round === checkRd);
  const checkDone = checkGames.length > 0 && checkGames.every(g => g.completed);
  // Also check previous round if current has no completed games
  const prevRd = rd > 0 ? rd - 1 : null;
  const prevGames = prevRd != null ? state.games.filter(g => g.round === prevRd) : [];
  const prevDone = !checkDone && prevGames.length > 0 && prevGames.every(g => g.completed);
  const recapRd = checkDone ? checkRd : prevDone ? prevRd : null;
  const recapGames = recapRd != null ? state.games.filter(g => g.round === recapRd) : [];
  const recap = recapRd != null ? (() => {
    const steals = recapGames.filter(g => g.transferInfo?.stolen).length;
    const covers = recapGames.length - steals;
    const aliveNow = state.teams.filter(t => t.alive).length;
    const odds = calcOdds(state);
    const top = odds[0];
    const bigGame = recapGames.filter(g=>g.transferInfo?.stolen).sort((a,b)=>Math.abs(b.margin-(b.spread||0))-Math.abs(a.margin-(a.spread||0)))[0];
    const bigMatchup = bigGame ? `${state.teams.find(t=>t.id===bigGame.team1Id)?.name} vs ${state.teams.find(t=>t.id===bigGame.team2Id)?.name}` : null;
    return { round: RDS[recapRd], games: recapGames.length, steals, covers, aliveNow, topName: top?.name, topPct: top?.pct, bigMatchup, bigTalk: bigGame?.transferInfo?.talk };
  })() : null;
  return (
    <div style={{padding:20,maxWidth:600,margin:"0 auto",boxSizing:"border-box",overflowX:"hidden"}}>
      <div style={{textAlign:"center",marginBottom:20}}>
        <div style={{fontSize:42}}>📢</div>
        <h2 style={{fontSize:28,fontWeight:800,color:"#fff",fontFamily:"'Oswald',sans-serif",margin:"8px 0 4px"}}>DRAMA FEED</h2>
        <p style={{color:"#7B8CA8",fontSize:16}}>Every steal, every upset, every transfer</p>
      </div>

      {/* Chat input */}
      <div style={{display:"flex",gap:8,marginBottom:16}}>
        <input value={msg} onChange={e=>setMsg(e.target.value)} onKeyDown={e=>{if(e.key==="Enter"&&msg.trim()){const entry={type:"chat",team:"",detail:msg.trim(),round:RDS[state.currentRound],matchup:player?.name||"Anon",ts:Date.now()};PN({...state,feed:[...(state.feed||[]),entry]});setMsg("");}}} placeholder={`${player?.name||"Anon"}, talk yo shit!`} style={{...I,flex:1,fontSize:17,borderRadius:20,padding:"10px 16px"}} />
        <button onClick={()=>{if(!msg.trim())return;const entry={type:"chat",team:"",detail:msg.trim(),round:RDS[state.currentRound],matchup:player?.name||"Anon",ts:Date.now()};PN({...state,feed:[...(state.feed||[]),entry]});setMsg("");}} style={{background:player?.color||"#FF6B35",border:"none",borderRadius:20,padding:"10px 16px",color:"#fff",fontWeight:700,fontSize:17,cursor:"pointer"}}>Send</button>
      </div>

      {/* Round Recap Card */}
      {recap&&<div style={{background:"linear-gradient(135deg,#1A2540,#131D2F)",borderRadius:12,padding:16,marginBottom:16,border:"1px solid #FF6B3540",animation:"fadeUp 0.4s ease both"}}>
        <div style={{fontSize:13,fontWeight:700,color:"#FF6B35",letterSpacing:2,marginBottom:10}}>📋 {recap.round} RECAP</div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8,marginBottom:12}}>
          <div style={{background:"#0B1120",borderRadius:8,padding:10,textAlign:"center"}}><div style={{fontSize:28,fontWeight:900,color:"#A855F7"}}>{recap.steals}</div><div style={{fontSize:10,color:"#7B8CA8",letterSpacing:1}}>STEALS</div></div>
          <div style={{background:"#0B1120",borderRadius:8,padding:10,textAlign:"center"}}><div style={{fontSize:28,fontWeight:900,color:"#00D4AA"}}>{recap.covers}</div><div style={{fontSize:10,color:"#7B8CA8",letterSpacing:1}}>COVERS</div></div>
          <div style={{background:"#0B1120",borderRadius:8,padding:10,textAlign:"center"}}><div style={{fontSize:28,fontWeight:900,color:"#fff"}}>{recap.aliveNow}</div><div style={{fontSize:10,color:"#7B8CA8",letterSpacing:1}}>ALIVE</div></div>
        </div>
        <div style={{fontSize:16,color:"#B8C5D4"}}>{recap.steals>0?`${recap.steals} ownership change${recap.steals>1?"s":""} across ${recap.games} games.`:`Clean round — all ${recap.games} covers, no steals.`} <span style={{color:"#FF6B35",fontWeight:700}}>{recap.topName}</span> leads at {recap.topPct}%.</div>
        {recap.bigMatchup&&<div style={{marginTop:10,background:"#0B1120",borderRadius:8,padding:10,borderLeft:"3px solid #FFD700"}}><div style={{fontSize:12,fontWeight:700,color:"#FFD700",letterSpacing:1,marginBottom:4}}>🏅 GAME OF THE ROUND</div><div style={{fontSize:16,fontWeight:700,color:"#fff"}}>{recap.bigMatchup}</div>{recap.bigTalk&&<div style={{fontSize:13,color:"#FBBF24",fontStyle:"italic",marginTop:4}}>💬 {recap.bigTalk}</div>}</div>}
      </div>}

      {feed.length===0&&<div style={{textAlign:"center",padding:40,color:"#7B8CA8"}}><div style={{fontSize:60,marginBottom:12}}>🦗</div><div style={{fontSize:18}}>No drama yet. Games haven't been resolved.</div><div style={{fontSize:16,marginTop:8}}>Once games start getting resolved, every transfer and cover will show up here.</div></div>}
      {(()=>{
        let lastRound=null;
        return feed.map((f,i)=>{
        const isSteal = f.type==="transfer";
        const isCover = f.type==="cover";
        const isChat = f.type==="chat";
        const showRoundHeader = !isChat && f.round!==lastRound;
        if(!isChat) lastRound=f.round;
        return <div key={i}>
          {showRoundHeader&&<div style={{fontSize:13,fontWeight:700,color:"#FF6B35",letterSpacing:2,margin:"16px 0 8px",textAlign:"center"}}>{f.round}</div>}
          {isChat ? <div style={{background:"#131D2F",borderRadius:10,padding:12,marginBottom:8,borderLeft:`3px solid ${state.players.find(p=>p.name===f.matchup)?.color||"#7B8CA8"}`,animation:`fadeUp 0.3s ease ${Math.min(i,10)*0.03}s both`}}>
            <div style={{display:"flex",alignItems:"center",gap:10}}>
              <PlayerAv player={state.players.find(p=>p.name===f.matchup)} avatars={avatars} size={36} />
              <div style={{flex:1}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}><span style={{fontSize:16,fontWeight:700,color:state.players.find(p=>p.name===f.matchup)?.color||"#fff"}}>{f.matchup}</span>{f.ts&&<span style={{fontSize:12,color:"#7B8CA8"}}>{timeAgo(f.ts)}</span>}</div>
                <div style={{fontSize:17,color:"#B8C5D4",marginTop:3}}>{f.detail}</div>
              </div>
            </div>
          </div> :
          <div style={{background:"#131D2F",borderRadius:10,padding:14,marginBottom:8,borderLeft:`3px solid ${isSteal?"#A855F7":isCover?"#00D4AA":"#7B8CA8"}`,animation:`fadeUp 0.3s ease ${Math.min(i,10)*0.03}s both`}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
            <div style={{flex:1}}>
              <div style={{fontSize:17,fontWeight:700,color:"#fff"}}>{isSteal?"🚨 STEAL":isCover?"✅ COVERED":"📋 RESULT"} — {f.team}</div>
              <div style={{fontSize:16,color:"#B8C5D4",marginTop:4}}>{f.detail}</div>
              <div style={{fontSize:13,color:"#7B8CA8",marginTop:4}}>{f.matchup}{f.ts?` • ${timeAgo(f.ts)}`:""}</div>
            </div>
          </div>
        </div>}</div>;
      });})()}
    </div>
  );
}

// --- BRACKET MANAGER ---
function BM({ state, P, PN, go, eg, setEg, scores, sl, refresh, player, triggerFlash, setNotification, onTeam }) {
  const [rd, setRd] = useState(state.currentRound);
  const rG=state.games.filter(g=>g.round===rd), al=state.teams.filter(t=>t.alive);
  const asgn=new Set(); rG.forEach(g=>{if(g.team1Id!=null)asgn.add(g.team1Id);if(g.team2Id!=null)asgn.add(g.team2Id);});

  const add=()=>{const g={id:Date.now(),round:rd,team1Id:null,team2Id:null,spread:0,winnerId:null,margin:null,completed:false,transferInfo:null,gameDate:"",gameTime:""};PN({...state,games:[...state.games,g]});setEg(g.id);};

  const importRound=async()=>{
    const existing=new Set();rG.forEach(g=>{if(g.team1Id!=null)existing.add(g.team1Id);if(g.team2Id!=null)existing.add(g.team2Id);});
    const aliveTeams=al.filter(t=>!existing.has(t.id));
    // Fetch multiple days of scores around tournament time
    const today=new Date(); const days=new Set();
    // Always check today +/- 3 days
    for(let d=-3;d<=3;d++){const dt=new Date(today);dt.setDate(dt.getDate()+d);days.add(dt.toISOString().split("T")[0].replace(/-/g,""));}
    // Round-specific tournament dates (2026)
    const RD_DATES=[["20260318","20260319"],["20260320","20260321"],["20260322","20260323"],["20260327","20260328"],["20260329","20260330"],["20260405","20260407"]];
    if(RD_DATES[rd])RD_DATES[rd].forEach(d=>days.add(d));
    // Also check next round dates
    if(RD_DATES[rd+1])RD_DATES[rd+1].forEach(d=>days.add(d));
    let allScores=[];
    for(const day of [...days]){const s=await fetchScores(day);allScores=allScores.concat(s);}
    // Dedupe by ESPN event ID
    const seen=new Set();allScores=allScores.filter(s=>{if(seen.has(s.id))return false;seen.add(s.id);return true;});
    // Match ESPN games to our alive teams
    let newGames=[];
    for(const ev of allScores){
      const m1=aliveTeams.find(t=>ev.teams.some(lt=>fz(t,lt.name,lt.abbr)));
      if(!m1)continue;
      const m2=aliveTeams.find(t=>t.id!==m1.id&&ev.teams.some(lt=>fz(t,lt.name,lt.abbr)));
      if(!m2)continue;
      if(existing.has(m1.id)||existing.has(m2.id))continue;
      // Parse spread from ESPN odds
      let spread=0;
      if(ev.spread){const sp=ev.spread.match(/([-+]?\d+\.?\d*)/);if(sp)spread=Math.abs(parseFloat(sp[1]));}
      // Determine fav/dog by spread or seed
      const fav=m1.seed<=m2.seed?m1:m2; const dog=m1.seed<=m2.seed?m2:m1;
      const dt=new Date(ev.date);
      const gameDate=dt.toISOString().split("T")[0];
      const gameTime=dt.toLocaleTimeString("en-US",{hour:"2-digit",minute:"2-digit",hour12:false}).slice(0,5);
      newGames.push({id:Date.now()+newGames.length,round:rd,team1Id:fav.id,team2Id:dog.id,spread,winnerId:null,margin:null,completed:false,transferInfo:null,gameDate,gameTime});
      existing.add(fav.id);existing.add(dog.id);
    }
    if(newGames.length>0)PN({...state,games:[...state.games,...newGames]});
    return newGames.length;
  };
  const [importing,setImporting]=useState(false);
  const [importCount,setImportCount]=useState(null);
  const doImport=async()=>{setImporting(true);const n=await importRound();setImportCount(n);setImporting(false);setTimeout(()=>setImportCount(null),3000);};
  const upd=(id,u)=>P({...state,games:state.games.map(g=>g.id===id?{...g,...u}:g)});
  const del=(id)=>{PN({...state,games:state.games.filter(g=>g.id!==id)});if(eg===id)setEg(null);};

  const res=(game)=>{
    const r=spreadResult(game,state.teams); if(!r)return;
    const matchup=`${r.fav.name} vs ${r.dog.name}`;
    const fromOwner=state.players[r.winner.currentOwner]?.name;
    const newOwner=state.players[r.spreadWinner]?.name;
    let ti, feedItem;
    if (r.stolen) {
      ti={advancer:r.winner.name,from:fromOwner,to:newOwner,stolen:true,talk:trashTalk({advancer:r.winner.name,from:fromOwner,to:newOwner},game.margin,r.sv)};
      feedItem={type:"transfer",team:r.winner.name,detail:`🚨 ${r.winner.name} won but ${fromOwner} didn't cover ${r.favWon?`-${r.sv}`:`+${r.sv}`}! ${newOwner} steals control of ${r.winner.name} going forward.`,round:RDS[rd],matchup,ts:Date.now()};
    } else {
      ti={advancer:r.winner.name,from:fromOwner,to:newOwner,stolen:false};
      const coverMsg = r.favWon ? `${fromOwner} covered -${r.sv} and keeps control.` : `${fromOwner}'s underdog won outright — keeps control.`;
      feedItem={type:"cover",team:r.winner.name,detail:`✅ ${r.winner.name} advances. ${coverMsg}`,round:RDS[rd],matchup,ts:Date.now()};
    }
    const nt=state.teams.map(t=>{
      if(t.id===r.loserId) return{...t,alive:false,eliminatedRound:rd};
      if(t.id===r.winnerId && r.stolen) return{...t,currentOwner:r.spreadWinner,transferHistory:[...(t.transferHistory||[]),r.winner.currentOwner]};
      return t;
    });
    const newFeed=[...(state.feed||[]),feedItem].filter(Boolean);
    PN({...state,teams:nt,games:state.games.map(g=>g.id===game.id?{...g,completed:true,transferInfo:ti}:g),feed:newFeed});
    triggerFlash(r.stolen?"steal":"cover");
    setNotification({type:r.stolen?"steal":"cover",team:r.winner.name,from:ti.from,to:ti.to,stolen:r.stolen});
    setEg(null);
  };

  const undo=(game)=>{
    const loserId=game.team1Id===game.winnerId?game.team2Id:game.team1Id;
    const ti=game.transferInfo;
    const wasStolen=ti&&ti.stolen;
    const nt=state.teams.map(t=>{
      if(t.id===loserId) return{...t,alive:true,eliminatedRound:null};
      if(t.id===game.winnerId && wasStolen){
        const prev=state.players.find(p=>p.name===ti.from)?.id;
        return{...t,currentOwner:prev??t.currentOwner,transferHistory:(t.transferHistory||[]).slice(0,-1)};
      }
      return t;
    });
    // Remove the feed entry for this game (match by team name + round)
    const advancer=ti?.advancer;
    const matchup=`${state.teams.find(t2=>t2.id===game.team1Id)?.name} vs ${state.teams.find(t2=>t2.id===game.team2Id)?.name}`;
    const cleanFeed=(state.feed||[]).filter(f=>!(f.team===advancer&&f.matchup===matchup&&f.round===RDS[rd]));
    PN({...state,teams:nt,games:state.games.map(g=>g.id===game.id?{...g,completed:false,winnerId:null,margin:null,transferInfo:null}:g),feed:cleanFeed});
  };
  const findLv=(g)=>{const t1=state.teams.find(t=>t.id===g.team1Id),t2=state.teams.find(t=>t.id===g.team2Id);if(!t1||!t2)return null;return scores.find(ls=>ls.teams.some(lt=>fz(t1,lt.name,lt.abbr))&&ls.teams.some(lt=>fz(t2,lt.name,lt.abbr)));};
  const setR=(r)=>{if(r>=0&&r<=5)setRd(r);};

  return (
    <div style={{padding:20,maxWidth:600,margin:"0 auto",boxSizing:"border-box",overflowX:"hidden"}}>
      <div style={{display:"flex",justifyContent:"space-between",marginBottom:12}}>
        <div style={{fontSize:14,color:"#FF6B35",fontWeight:700,letterSpacing:2}}>GAME CENTER</div>
        <button onClick={()=>refresh()} style={{...B(sl?"#1E3050":"#131D2F",sl?"#7B8CA8":"#00D4AA","1px solid #1E3050"),fontSize:14,padding:"6px 12px"}}>{sl?"⏳":"📡"} SCORES</button>
      </div>

      {/* Round tabs */}
      <div style={{display:"flex",gap:4,marginBottom:16,overflowX:"auto",scrollbarWidth:"none",paddingBottom:4}}>
        {RDS.map((r,i)=>{const rGames=state.games.filter(g=>g.round===i);if(rGames.length===0)return null;const done=rGames.length>0&&rGames.every(g=>g.completed);return <button key={i} onClick={()=>setR(i)} style={{background:i===rd?"#FF6B3530":"transparent",border:`1px solid ${i===rd?"#FF6B35":"#1E3050"}`,borderRadius:20,padding:"8px 16px",cursor:"pointer",whiteSpace:"nowrap",fontSize:14,fontWeight:700,color:i===rd?"#FF6B35":"#7B8CA8",transition:"all 0.2s",position:"relative"}}>{RDE[i]} {r} {done?"✓":rGames.length>0?<span style={{fontSize:10,color:"#7B8CA8",marginLeft:4}}>({rGames.filter(g=>g.completed).length}/{rGames.length})</span>:""}</button>;})}
      </div>

      <div style={{textAlign:"center",marginBottom:16}}>
        <div style={{fontSize:32,fontWeight:800,color:"#fff",fontFamily:"'Oswald',sans-serif"}}>{RDE[rd]} {RDS[rd]}</div>
        <div style={{fontSize:16,color:"#7B8CA8",marginTop:4}}>{al.length} alive • {rG.length} games</div>
      </div>

      {/* Quick stats bar */}
      {rG.length>0&&<div style={{display:"flex",gap:6,marginBottom:16}}>
        <div style={{flex:1,background:"#131D2F",borderRadius:8,padding:"8px 0",textAlign:"center",border:"1px solid #1E3050"}}>
          <div style={{fontSize:21,fontWeight:800,color:"#00D4AA"}}>{rG.filter(g=>g.completed).length}</div>
          <div style={{fontSize:10,color:"#7B8CA8",letterSpacing:1}}>RESOLVED</div>
        </div>
        <div style={{flex:1,background:"#131D2F",borderRadius:8,padding:"8px 0",textAlign:"center",border:"1px solid #1E3050"}}>
          <div style={{fontSize:21,fontWeight:800,color:"#FBBF24"}}>{rG.filter(g=>!g.completed).length}</div>
          <div style={{fontSize:10,color:"#7B8CA8",letterSpacing:1}}>PENDING</div>
        </div>
        <div style={{flex:1,background:"#131D2F",borderRadius:8,padding:"8px 0",textAlign:"center",border:"1px solid #1E3050"}}>
          <div style={{fontSize:21,fontWeight:800,color:"#A855F7"}}>{rG.filter(g=>g.transferInfo?.stolen).length}</div>
          <div style={{fontSize:10,color:"#7B8CA8",letterSpacing:1}}>STEALS</div>
        </div>
      </div>}

      {/* Live game cards */}
      {(()=>{
        const liveGames=state.games.filter(g=>!g.completed&&g.team1Id!=null&&g.team2Id!=null).filter(g=>{
          const t1x=state.teams.find(t=>t.id===g.team1Id),t2x=state.teams.find(t=>t.id===g.team2Id);
          return scores.some(ls=>isLive(ls.status)&&t1x&&t2x&&ls.teams.some(lt=>fz(t1x,lt.name,lt.abbr))&&ls.teams.some(lt=>fz(t2x,lt.name,lt.abbr)));
        });
        if(liveGames.length===0)return null;
        return <div style={{marginBottom:12}}>
          <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:10}}>
            <div style={{width:8,height:8,borderRadius:"50%",background:"#FF4757",animation:"pulse 1.5s infinite"}} />
            <span style={{fontSize:12,fontWeight:700,color:"#FF4757",letterSpacing:2}}>LIVE NOW</span>
          </div>
          {liveGames.map(g=><LiveCard key={g.id} game={g} state={state} scores={scores} onTeam={onTeam} myPlayerId={player?.id} />)}
        </div>;
      })()}

      {/* Games with rivalry badges — sorted: pending by date, completed last */}
      {rG.length===0&&<div style={{textAlign:"center",padding:40,color:"#7B8CA8"}}><div style={{fontSize:60,marginBottom:12}}>📋</div><div style={{fontSize:18,fontWeight:600}}>No games yet for {RDS[rd]}</div><div style={{fontSize:16,marginTop:8}}>Games will appear here as the tournament progresses.</div></div>}
      {rG.length>0&&<div style={{background:"#0B1120",borderRadius:6,height:4,marginBottom:12,overflow:"hidden"}}><div style={{background:"linear-gradient(90deg,#FF6B35,#00D4AA)",height:"100%",width:`${rG.filter(g=>g.completed).length/rG.length*100}%`,borderRadius:6,transition:"width 0.5s ease"}} /></div>}
      {[...rG].sort((a,b)=>{
        if(a.completed!==b.completed)return a.completed?1:-1;
        // Both pending: live games first
        const aLv=findLv(a),bLv=findLv(b);
        const aLive=isLive(aLv?.status)?1:0;
        const bLive=isLive(bLv?.status)?1:0;
        if(aLive!==bLive)return bLive-aLive;
        const da=`${a.gameDate||"9999"}${a.gameTime||"99:99"}`;
        const db=`${b.gameDate||"9999"}${b.gameTime||"99:99"}`;
        return da.localeCompare(db);
      }).map(g=>{
        const t1=state.teams.find(t=>t.id===g.team1Id),t2=state.teams.find(t=>t.id===g.team2Id);
        const o1=t1?state.players[t1.currentOwner]:null,o2=t2?state.players[t2.currentOwner]:null;
        const rivalry=o1&&o2&&o1.id!==o2.id;
        const sameOwner=o1&&o2&&o1.id===o2.id;
        return <div key={g.id}>
          {/* Rivalry badge */}
          {rivalry&&!g.completed&&<div style={{display:"flex",justifyContent:"center",marginBottom:4}}>
            <span style={{background:"#FF6B3520",border:"1px solid #FF6B3540",borderRadius:20,padding:"2px 12px",fontSize:13,fontWeight:700,color:"#FF6B35"}}>🔥 {o1.name} vs {o2.name}</span>
          </div>}
          {sameOwner&&!g.completed&&<div style={{display:"flex",justifyContent:"center",marginBottom:4}}>
            <span style={{background:"#00D4AA20",border:"1px solid #00D4AA40",borderRadius:20,padding:"2px 12px",fontSize:13,fontWeight:700,color:"#00D4AA"}}>😮‍💨 Both {o1.name}'s — safe game</span>
          </div>}
          <GC g={g} state={state} upd={upd} del={del} res={res} undo={undo} ed={eg===g.id} setEd={setEg} asgn={asgn} lv={findLv(g)} />
        </div>;
      })}
      {rG.length>0&&rG.every(g=>g.completed)&&state.currentRound<5&&<div style={{textAlign:"center",marginTop:16,padding:16,background:"#131D2F",borderRadius:10,border:"1px solid #FF6B3540"}}><div style={{fontSize:17,fontWeight:700,color:"#FF6B35"}}>Round complete! Commissioner can advance to {RDS[rd+1]} in Admin.</div></div>}
    </div>
  );
}

function GC({g,state,upd,del,res,undo,ed,setEd,asgn,lv}){const [confirmDel,setConfirmDel]=useState(false);const t1=state.teams.find(t=>t.id===g.team1Id),t2=state.teams.find(t=>t.id===g.team2Id);const o1=t1?state.players[t1.currentOwner]:null,o2=t2?state.players[t2.currentOwner]:null;const al=state.teams.filter(t=>t.alive);const av=al.filter(t=>!asgn.has(t.id)||t.id===g.team1Id||t.id===g.team2Id);const il=isLive(lv?.status),fi=lv?.status==="STATUS_FINAL";
  if(g.completed){const w=state.teams.find(t=>t.id===g.winnerId),l=t1?.id===g.winnerId?t2:t1;const ti=g.transferInfo;return <div style={{background:"#131D2F",borderRadius:10,marginBottom:8,borderLeft:`3px solid ${ti&&ti.stolen?"#FF4757":"#00D4AA"}`,overflow:"hidden"}}><div style={{padding:14}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}><div><span style={{color:"#00D4AA",fontWeight:700}}>✓ {w?.name}</span><span style={{color:"#7B8CA8"}}> def. </span><span style={{color:"#FF4757"}}>{l?.name}</span><span style={{color:"#7B8CA8",fontSize:16}}> by {g.margin}</span>{g.spread!==0&&<span style={{color:"#7B8CA8",fontSize:14}}> (+{Math.abs(g.spread)})</span>}</div><button onClick={()=>undo(g)} style={{background:"none",border:"1px solid #2A3A5C",borderRadius:8,color:"#7B8CA8",fontSize:13,padding:"8px 12px",cursor:"pointer"}}>UNDO</button></div>{g.gameDate&&<div style={{fontSize:13,color:"#7B8CA8",marginTop:4}}>{fmtDate(g.gameDate,g.gameTime)}</div>}{ti&&<div style={{fontSize:14,marginTop:4,fontWeight:600,color:ti.stolen?"#FF4757":"#00D4AA"}}>{ti.stolen?`🚨 ${ti.advancer} now controlled by ${ti.to} (stolen from ${ti.from})`:`✅ ${ti.advancer} advances — ${ti.to} keeps control`}</div>}{ti?.talk&&<div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginTop:6,background:"#0B1120",borderRadius:6,padding:"6px 10px"}}><span style={{fontSize:13,color:"#FBBF24",fontStyle:"italic"}}>💬 {ti.talk}</span><button onClick={()=>navigator.clipboard?.writeText(ti.talk)} style={{background:"none",border:"none",color:"#7B8CA8",fontSize:13,cursor:"pointer",flexShrink:0,marginLeft:8}}>📋</button></div>}</div></div>;}
  if(!ed)return <div onClick={()=>setEd(g.id)} style={{background:"#131D2F",borderRadius:10,marginBottom:8,cursor:"pointer",border:`1px solid ${il?"#FF475740":"#1E3050"}`,overflow:"hidden"}}><div style={{padding:14}}>{g.gameDate&&<div style={{display:"flex",justifyContent:"space-between",marginBottom:8,fontSize:13,color:"#7B8CA8"}}><span>{fmtDate(g.gameDate,g.gameTime)}</span>{g.spread!==0?<span style={{color:"#FF6B35",fontWeight:700}}>+{Math.abs(g.spread)}</span>:<span style={{color:"#7B8CA8",fontWeight:600}}>Pick'em</span>}</div>}<div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}><div style={{display:"flex",alignItems:"center",gap:8}}><Logo name={t1?.name} size={20} /><div><span style={{color:"#fff",fontWeight:600,fontSize:17,display:"block"}}>{t1?.name||"Select"}</span>{o1&&<span style={{fontSize:12,color:o1.color}}>{o1.name}</span>}</div></div><span style={{color:"#FF6B35",fontWeight:700,fontSize:16}}>vs</span><div style={{display:"flex",alignItems:"center",gap:8,flexDirection:"row-reverse"}}><Logo name={t2?.name} size={20} /><div style={{textAlign:"right"}}><span style={{color:"#fff",fontWeight:600,fontSize:17,display:"block"}}>{t2?.name||"Select"}</span>{o2&&<span style={{fontSize:12,color:o2.color}}>{o2.name}</span>}</div></div></div></div>{lv&&(il||fi)&&<div style={{background:"#0B1120",padding:"6px 14px",display:"flex",justifyContent:"space-between",alignItems:"center",borderTop:"1px solid #1E3050"}}><span style={{fontSize:16,fontWeight:700,color:"#fff"}}>{lv.away?.abbr} {lv.away?.score} — {lv.home?.score} {lv.home?.abbr}</span><LBg s={lv.status} d={lv.detail} ck={lv.clock} pr={lv.period}/></div>}</div>;
  const pv=spreadResult(g,state.teams);
  return <div style={{background:"#131D2F",borderRadius:10,padding:16,marginBottom:8,border:"1px solid #FF6B35"}}><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:12}}><div><label style={lb}>DATE</label><input type="date" value={g.gameDate||""} onChange={e=>upd(g.id,{gameDate:e.target.value})} style={{...I,width:"100%"}}/></div><div><label style={lb}>TIME</label><input type="time" value={g.gameTime||""} onChange={e=>upd(g.id,{gameTime:e.target.value})} style={{...I,width:"100%"}}/></div></div><div style={{display:"grid",gridTemplateColumns:"1fr auto 1fr",gap:8,alignItems:"start",marginBottom:12}}><div><label style={lb}>FAVORITE</label><select value={g.team1Id??""} onChange={e=>upd(g.id,{team1Id:e.target.value===""?null:parseInt(e.target.value)})} style={{...I,width:"100%"}}><option value="">Select...</option>{av.filter(t=>t.id!==g.team2Id).map(t=><option key={t.id} value={t.id}>({t.seed}) {t.name}</option>)}</select>{o1&&<div style={{fontSize:13,color:o1.color,marginTop:3}}>{o1.name}</div>}</div><div style={{color:"#FF6B35",fontWeight:700,fontSize:18,paddingTop:22}}>vs</div><div><label style={lb}>UNDERDOG</label><select value={g.team2Id??""} onChange={e=>upd(g.id,{team2Id:e.target.value===""?null:parseInt(e.target.value)})} style={{...I,width:"100%"}}><option value="">Select...</option>{av.filter(t=>t.id!==g.team1Id).map(t=><option key={t.id} value={t.id}>({t.seed}) {t.name}</option>)}</select>{o2&&<div style={{fontSize:13,color:o2.color,marginTop:3}}>{o2.name}</div>}</div></div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8,marginBottom:12}}><div><label style={lb}>SPREAD</label><input type="number" step="0.5" value={g.spread||""} onChange={e=>upd(g.id,{spread:parseFloat(e.target.value)||0})} style={{...I,width:"100%"}} placeholder="16.5"/></div><div><label style={lb}>WINNER</label><select value={g.winnerId??""} onChange={e=>upd(g.id,{winnerId:e.target.value===""?null:parseInt(e.target.value)})} style={{...I,width:"100%"}}><option value="">...</option>{g.team1Id!=null&&<option value={g.team1Id}>{state.teams.find(t=>t.id===g.team1Id)?.name}</option>}{g.team2Id!=null&&<option value={g.team2Id}>{state.teams.find(t=>t.id===g.team2Id)?.name}</option>}</select></div><div><label style={lb}>MARGIN</label><input type="number" value={g.margin??""} onChange={e=>upd(g.id,{margin:e.target.value===""?null:parseInt(e.target.value)})} style={{...I,width:"100%"}} placeholder="pts"/></div></div>{lv&&fi&&!g.completed&&<button onClick={()=>{const h=lv.home,a=lv.away;const w=h.score>a.score?h:a;const wid=t1&&fz(t1,w.name||"",w.abbr||"")?g.team1Id:g.team2Id;upd(g.id,{winnerId:wid,margin:Math.abs(h.score-a.score)});}} style={{...B("#00D4AA20","#00D4AA","1px solid #00D4AA40"),width:"100%",marginBottom:12,fontSize:16,padding:"8px"}}>📡 AUTO: {lv.away?.abbr} {lv.away?.score} — {lv.home?.score} {lv.home?.abbr}</button>}{pv&&<div style={{background:"#0B1120",borderRadius:8,padding:10,marginBottom:12,fontSize:16}}>{pv.stolen?<span style={{color:"#FF4757"}}>🚨 {pv.winner.name} wins but {state.players[pv.winner.currentOwner]?.name} didn't cover! {state.players[pv.spreadWinner]?.name} steals control.</span>:<span style={{color:"#00D4AA"}}>✅ {pv.winner.name} advances. {state.players[pv.spreadWinner]?.name} keeps control (covered).</span>}
      {(()=>{const shifts=oddsShift(pv,state);if(!shifts||shifts.length===0)return null;return <div style={{marginTop:8,borderTop:"1px solid #1E3050",paddingTop:8}}><div style={{fontSize:12,color:"#7B8CA8",fontWeight:700,letterSpacing:1,marginBottom:4}}>ODDS SHIFT</div>{shifts.map(p=><div key={p.id} style={{display:"flex",justifyContent:"space-between",fontSize:14,color:p.color,marginBottom:2}}><span>{p.name}</span><span>{p.cur}% → {p.next}% <span style={{color:p.diff>0?"#00D4AA":"#FF4757"}}>({p.diff>0?"+":""}{p.diff})</span></span></div>)}</div>;})()}</div>}
      {/* What If — show the other outcome */}
      {pv&&g.winnerId!=null&&g.margin!=null&&g.spread!==0&&(()=>{
        const altWinnerId=g.winnerId;const altMargin=g.margin;
        const wouldSteal=pv.stolen;
        const altGame={...g,margin:wouldSteal?(Math.abs(g.spread)+1):(Math.abs(g.spread)-1)};
        const altPv=spreadResult(altGame,state.teams);
        if(!altPv||altPv.stolen===pv.stolen)return null;
        return <div style={{background:"#0B112080",borderRadius:8,padding:10,marginBottom:12,fontSize:14,border:"1px dashed #2A3A5C"}}>
          <div style={{fontSize:12,color:"#7B8CA8",fontWeight:700,letterSpacing:1,marginBottom:4}}>💭 WHAT IF {wouldSteal?"THEY COVERED":"THEY DIDN'T COVER"}?</div>
          <div style={{color:altPv.stolen?"#FF4757":"#00D4AA"}}>{altPv.stolen?`🚨 ${state.players[altPv.spreadWinner]?.name} would steal ${altPv.winner.name}`:`✅ ${state.players[altPv.spreadWinner]?.name} would keep ${altPv.winner.name}`}</div>
        </div>;
      })()}<div style={{display:"flex",gap:8}}>{confirmDel?<><button onClick={()=>setConfirmDel(false)} style={{...B("transparent","#7B8CA8","1px solid #2A3A5C"),fontSize:16,padding:"8px 12px"}}>NEVERMIND</button><button onClick={()=>{del(g.id);setConfirmDel(false);}} style={{...B("#FF4757","#fff"),flex:1,fontSize:16}}>YES DELETE</button></>:<><button onClick={()=>setConfirmDel(true)} style={{...B("transparent","#FF4757","1px solid #FF475740"),fontSize:16,padding:"8px 12px"}}>🗑</button><button onClick={()=>setEd(null)} style={{...B("transparent","#7B8CA8","1px solid #2A3A5C"),flex:1,fontSize:16}}>CANCEL</button><button onClick={()=>res(g)} disabled={!pv} style={{...B(pv?"#FF6B35":"#2A3A5C","#fff"),flex:1,fontSize:16,opacity:pv?1:0.5}}>RESOLVE ✓</button></>}</div></div>;
}

// --- ADMIN ---
function Admin({ state, PN, go, resetReveals, resetAvatars }) {
  const [pw, setPw] = useState("");
  const [unlocked, setUnlocked] = useState(false);
  const [cf,setCf]=useState(null);
  const [exportMsg,setExportMsg]=useState(null);
  const [manualXfer,setManualXfer]=useState(false);
  const [xferTeamId,setXferTeamId]=useState("");
  const [xferToOwner,setXferToOwner]=useState("");
  const fileRef=useRef(null);

  const exec=()=>{if(cf==="all"){PN(INIT);resetReveals();resetAvatars();}else if(cf==="games")PN({...state,teams:state.teams.map(t=>({...t,currentOwner:t.originalOwner,alive:true,eliminatedRound:null,transferHistory:[]})),games:R1_GAMES,currentRound:0,feed:[]});setCf(null);};

  const exportState=()=>{
    const blob=new Blob([JSON.stringify(state,null,2)],{type:"application/json"});
    const url=URL.createObjectURL(blob);
    const a=document.createElement("a");
    a.href=url;a.download=`march-mayhem-backup-${new Date().toISOString().split("T")[0]}.json`;
    a.click();URL.revokeObjectURL(url);
    setExportMsg("✓ Downloaded");setTimeout(()=>setExportMsg(null),3000);
  };

  const importState=(e)=>{
    const file=e.target.files?.[0];if(!file)return;
    const reader=new FileReader();
    reader.onload=(ev)=>{
      try{
        const data=JSON.parse(ev.target.result);
        if(data.players&&data.teams&&data.games!=null){PN(data);setExportMsg("✓ Imported!");setTimeout(()=>setExportMsg(null),3000);}
        else setExportMsg("❌ Invalid file");
      }catch(err){setExportMsg("❌ Parse error");}
      setTimeout(()=>setExportMsg(null),3000);
    };
    reader.readAsText(file);
    e.target.value="";
  };

  const doTransfer=()=>{
    const tid=parseInt(xferTeamId),pid=parseInt(xferToOwner);
    if(isNaN(tid)||isNaN(pid))return;
    const team=state.teams.find(t=>t.id===tid);
    if(!team)return;
    PN({...state,teams:state.teams.map(t=>t.id===tid?{...t,currentOwner:pid,transferHistory:[...(t.transferHistory||[]),t.currentOwner]}:t)});
    setManualXfer(false);setXferTeamId("");setXferToOwner("");
  };

  // League stats
  const totalGames=state.games.length;
  const completed=state.games.filter(g=>g.completed).length;
  const steals=state.games.filter(g=>g.transferInfo?.stolen).length;
  const alive=state.teams.filter(t=>t.alive).length;
  const teamsWithTransfers=state.teams.filter(t=>t.transferHistory?.length>0).length;

  return(
    <div style={{padding:20,maxWidth:500,margin:"0 auto",boxSizing:"border-box",overflowX:"hidden"}}>
      {!unlocked ? <>
        <H t="COMMISSIONER" s="Enter password to access" />
        <div style={{marginTop:24}}>
          <input type="password" value={pw} onChange={e=>setPw(e.target.value)} onKeyDown={e=>{if(e.key==="Enter"&&pw==="imgoinin")setUnlocked(true);}} placeholder="Password..." style={{...I,width:"100%",fontSize:21,textAlign:"center",padding:"14px",marginBottom:12}} />
          <button onClick={()=>{if(pw==="imgoinin")setUnlocked(true);else{setPw("");alert("Wrong password");}}} style={{...B("#FF6B35","#fff"),width:"100%",fontSize:18}}>UNLOCK 🔐</button>
          <button onClick={()=>go("select")} style={{...B("transparent","#7B8CA8"),width:"100%",marginTop:8,fontSize:16}}>← Back to Players</button>
        </div>
      </> : <>
      <H t="COMMISSIONER" s="League tools" />

      {/* League Stats */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:6,marginBottom:20}}>
        <div style={{background:"#131D2F",borderRadius:8,padding:8,textAlign:"center",border:"1px solid #1E3050"}}><div style={{fontSize:21,fontWeight:800,color:"#fff"}}>{alive}</div><div style={{fontSize:10,color:"#7B8CA8",letterSpacing:1}}>ALIVE</div></div>
        <div style={{background:"#131D2F",borderRadius:8,padding:8,textAlign:"center",border:"1px solid #1E3050"}}><div style={{fontSize:21,fontWeight:800,color:"#00D4AA"}}>{completed}</div><div style={{fontSize:10,color:"#7B8CA8",letterSpacing:1}}>GAMES</div></div>
        <div style={{background:"#131D2F",borderRadius:8,padding:8,textAlign:"center",border:"1px solid #1E3050"}}><div style={{fontSize:21,fontWeight:800,color:"#A855F7"}}>{steals}</div><div style={{fontSize:10,color:"#7B8CA8",letterSpacing:1}}>STEALS</div></div>
        <div style={{background:"#131D2F",borderRadius:8,padding:8,textAlign:"center",border:"1px solid #1E3050"}}><div style={{fontSize:21,fontWeight:800,color:"#FBBF24"}}>{teamsWithTransfers}</div><div style={{fontSize:10,color:"#7B8CA8",letterSpacing:1}}>XFERS</div></div>
        <div style={{background:"#131D2F",borderRadius:8,padding:8,textAlign:"center",border:"1px solid #1E3050"}}><div style={{fontSize:21,fontWeight:800,color:"#FF6B35"}}>{RDS[state.currentRound]?.split(" ")[0]}</div><div style={{fontSize:10,color:"#7B8CA8",letterSpacing:1}}>ROUND</div></div>
      </div>

      {cf&&<div style={{background:"#1a0a0a",border:"1px solid #FF4757",borderRadius:10,padding:16,marginBottom:16}}><div style={{color:"#FF4757",fontWeight:700,fontSize:18,marginBottom:8}}>{cf==="all"?"Factory reset?":"Reset games?"}</div><div style={{color:"#7B8CA8",fontSize:16,marginBottom:12}}>Cannot be undone.</div><div style={{display:"flex",gap:8}}><button onClick={()=>setCf(null)} style={{...B("#1E3050","#B8C5D4"),flex:1,fontSize:16}}>CANCEL</button><button onClick={exec} style={{...B("#FF4757","#fff"),flex:1,fontSize:16}}>CONFIRM</button></div></div>}

      {exportMsg&&<div style={{background:"#131D2F",borderRadius:8,padding:12,marginBottom:12,textAlign:"center",color:"#00D4AA",fontWeight:700,fontSize:17}}>{exportMsg}</div>}

      <Sec text="ROUND MANAGEMENT" />
      <div style={{display:"flex",flexDirection:"column",gap:10,marginBottom:16}}>
        <button onClick={()=>{const next=generateNextRound(state);if(next){PN(next);}else{alert("Can't generate yet — not all games in current round are resolved.");}}} style={{...B("#A855F720","#A855F7","1px solid #A855F740"),padding:14,fontSize:16}}>🏟️ AUTO-GENERATE NEXT ROUND BRACKET</button>
        <div style={{fontSize:13,color:"#7B8CA8",padding:"0 4px"}}>When all games in the current round are resolved, this will auto-create the next round matchups from the bracket.</div>
      </div>

      <Sec text="ACTIONS" />
      <div style={{display:"flex",flexDirection:"column",gap:10}}>
        <button onClick={()=>setCf("games")} style={B("#1E3050","#FBBF24")}>🔄 RESET GAMES</button>
        <button onClick={resetReveals} style={B("#1E3050","#B8C5D4")}>👀 RESET REVEALS</button>
        <button onClick={resetAvatars} style={B("#1E3050","#B8C5D4")}>📸 RESET AVATARS</button>
        <div style={{marginTop:16,background:"#0B1120",borderRadius:8,padding:12,border:"1px solid #1E3050"}}>
          <div style={{fontSize:13,fontWeight:700,color:"#FF6B35",letterSpacing:1,marginBottom:8}}>STORAGE DIAGNOSTIC</div>
          <div style={{fontSize:13,color:"#7B8CA8",fontFamily:"monospace",wordBreak:"break-all"}}>
            <div>cache-state: {(localStorage.getItem("cache-state")?.length||0)+" (supabase:"+(SUPA_REST?"ON":"off")+")"} chars</div>
            <div>mm-reveals-final: {localStorage.getItem("mm-reveals-final")||"null"}</div>
            <div>mm-avatars: {(()=>{const a=localStorage.getItem("mm-avatars");if(!a)return "null";const p=JSON.parse(a);return Object.keys(p).map(k=>k+":"+(p[k]==="skip"?"skip":p[k]?.substring(0,20)+"...")).join(", ")})()}</div>
            <div>feed items: {(()=>{try{const s=localStorage.getItem("cache-state");if(!s)return 0;return JSON.parse(s).feed?.length||0}catch(e){return"err"}})()}</div>
          </div>
        </div>
        <button onClick={()=>setCf("all")} style={B("#FF4757","#fff")}>🗑 FACTORY RESET</button>
      </div>

      <Sec text="BACKUP / RESTORE" />
      <div style={{display:"flex",gap:8}}>
        <button onClick={exportState} style={{...B("#1E3050","#00D4AA"),flex:1,fontSize:16}}>📥 Export JSON</button>
        <button onClick={()=>fileRef.current?.click()} style={{...B("#1E3050","#3B82F6"),flex:1,fontSize:16}}>📤 Import JSON</button>
        <input ref={fileRef} type="file" accept=".json" onChange={importState} style={{display:"none"}} />
      </div>

      <Sec text="MANUAL TRANSFER" />
      {!manualXfer?<button onClick={()=>setManualXfer(true)} style={{...B("#1E3050","#7B8CA8"),width:"100%",fontSize:16}}>🔧 Force Ownership Transfer</button>:
      <div style={{background:"#131D2F",borderRadius:10,padding:14,border:"1px solid #1E3050"}}>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:10}}>
          <div><label style={lb}>TEAM</label><select value={xferTeamId} onChange={e=>setXferTeamId(e.target.value)} style={{...I,width:"100%"}}><option value="">Pick team...</option>{state.teams.filter(t=>t.alive).map(t=><option key={t.id} value={t.id}>({t.seed}) {t.name} — {state.players[t.currentOwner]?.name}</option>)}</select></div>
          <div><label style={lb}>NEW OWNER</label><select value={xferToOwner} onChange={e=>setXferToOwner(e.target.value)} style={{...I,width:"100%"}}><option value="">Pick owner...</option>{state.players.map(p=><option key={p.id} value={p.id}>{p.name}</option>)}</select></div>
        </div>
        <div style={{display:"flex",gap:8}}>
          <button onClick={()=>setManualXfer(false)} style={{...B("transparent","#7B8CA8","1px solid #2A3A5C"),flex:1,fontSize:16}}>Cancel</button>
          <button onClick={doTransfer} disabled={!xferTeamId||!xferToOwner} style={{...B(xferTeamId&&xferToOwner?"#FF6B35":"#1E3050","#fff"),flex:1,fontSize:16,opacity:xferTeamId&&xferToOwner?1:0.5}}>Transfer</button>
        </div>
      </div>}

      <Sec text="📖 RULES" />
      <div style={{background:"#0B1120",border:"1px solid #1E3050",borderRadius:10,padding:14,marginBottom:8}}>
        <div style={{display:"flex",flexDirection:"column",gap:10}}>
          <RuleRow icon="📺" text="Every tournament game uses the ESPN closing spread." />
          <RuleRow icon="🏀" text="One team wins, one team is eliminated. Normal bracket." />
          <RuleRow icon="🔄" text="The spread winner takes control of whichever team advances. Win the game but lose the spread? You just lost your team." />
          <RuleRow icon="🤝" text="Tie goes to the underdog. Margin = spread means underdog wins the spread." />
          <RuleRow icon="🏆" text="Whoever controls the national champion at the end wins March Mayhem." />
        </div>
      </div>

      <div style={{marginTop:24}}><Sec text="ALL ROSTERS" />
        {state.players.map(p=>{const ts=state.teams.filter(t=>t.currentOwner===p.id);return <div key={p.id} style={{background:"#131D2F",borderRadius:8,padding:12,marginBottom:8}}><div style={{display:"flex",alignItems:"center",gap:8,marginBottom:6}}><div style={{width:10,height:10,borderRadius:"50%",background:p.color}}/><span style={{fontWeight:700,color:p.color,fontSize:17}}>{p.name}</span><span style={{color:"#7B8CA8",fontSize:14}}>({ts.filter(t=>t.alive).length}/{ts.length})</span></div><div style={{display:"flex",flexWrap:"wrap",gap:4}}>{ts.map(t=><span key={t.id} style={{fontSize:13,padding:"2px 6px",borderRadius:4,background:t.alive?"#0B1120":"#0A0A0A",color:t.alive?"#B8C5D4":"#4A5568",border:`1px solid ${t.alive?"#1E3050":"#1A1A2E"}`}}>({t.seed}) {t.name} <span style={{color:"#FF6B3580"}}>{t.espn}</span>{!t.alive&&" 💀"}{t.originalOwner!==t.currentOwner&&" 🔄"}</span>)}</div></div>;})}
      </div>

      {/* Advance Round */}
      {state.games.filter(g=>g.round===state.currentRound).length>0&&state.games.filter(g=>g.round===state.currentRound).every(g=>g.completed)&&state.currentRound<5&&<>
        <Sec text="ADVANCE ROUND" />
        <button onClick={()=>PN({...state,currentRound:state.currentRound+1})} style={{...B("#FF6B35","#fff"),width:"100%",fontSize:18}}>ADVANCE TO {RDS[state.currentRound+1]} →</button>
      </>}
      </>}
    </div>
  );
}
// --- LEADERBOARD ---
function LB({ state, me, champ, co, go, onTeam, avatars }) {
  const [expanded, setExpanded] = useState(null);
  const ranks=state.players.map(p=>{const ts=state.teams.filter(t=>t.currentOwner===p.id),a=ts.filter(t=>t.alive),st=ts.filter(t=>t.originalOwner!==p.id);const sk=calcStreak(state,p.id);return{...p,total:ts.length,alive:a.length,stolen:st.length,streak:sk,best:a.length>0?Math.min(...a.map(t=>t.seed)):99};}).sort((a,b)=>b.alive-a.alive||a.best-b.best||b.total-a.total);
  const odds = useMemo(() => calcOdds(state), [state]);
  const aliveCount = state.teams.filter(t => t.alive).length;
  const maxPct = Math.max(...odds.map(o => o.pct), 1);

  return(
    <div style={{padding:20,maxWidth:600,margin:"0 auto",boxSizing:"border-box",overflowX:"hidden"}}>
      {champ&&<><Confetti/><CC name={champ.name} owner={co}/></>}

      {/* Header */}
      <div style={{textAlign:"center",marginBottom:20}}>
        <div style={{fontSize:12,color:"#7B8CA8",letterSpacing:3,fontWeight:700,marginBottom:4}}>MARCH MAYHEM</div>
        <div style={{fontSize:32,fontWeight:900,fontFamily:"'Oswald',sans-serif",letterSpacing:2,color:"#fff"}}>POWER RANKINGS</div>
        {state.teams.filter(t=>t.alive).length<=16&&<button onClick={()=>go("spotlight")} style={{background:"linear-gradient(90deg,#FFD70030,#FF6B3530)",border:"1px solid #FFD70050",borderRadius:10,padding:"10px 20px",cursor:"pointer",color:"#FFD700",fontSize:14,fontWeight:700,marginTop:8,letterSpacing:1}}>🏟️ SPOTLIGHT MODE</button>}
        {state.teams.filter(t=>t.alive).length===1&&<button onClick={()=>go("yearbook")} style={{background:"linear-gradient(90deg,#FFD70030,#A855F730)",border:"1px solid #FFD70050",borderRadius:10,padding:"10px 20px",cursor:"pointer",color:"#FFD700",fontSize:14,fontWeight:700,marginTop:8,marginLeft:8,letterSpacing:1}}>📖 SEASON RECAP</button>}
        <div style={{fontSize:14,color:"#7B8CA8",marginTop:4}}>{RDS[state.currentRound]} • {aliveCount} teams alive</div>
      </div>

      {ranks.map((p,i)=>{
        const isMe=me?.id===p.id;
        const isTop3=i<3;
        const isExp=expanded===i;
        const aliveTeams=state.teams.filter(t=>t.alive&&t.currentOwner===p.id).sort((a,b)=>a.seed-b.seed);
        const pOdds=odds.find(o=>o.id===p.id);
        const pct=pOdds?.pct||0;
        const rank=i+1;
        return <div key={p.id} onClick={()=>setExpanded(isExp?null:i)} style={{
          background:isMe?`${p.color}10`:"#131D2F",
          borderRadius:14,padding:"14px 14px 10px",
          marginBottom:isTop3?10:6,
          border:isMe?`2px solid ${p.color}50`:isTop3?`1px solid ${p.color}30`:"1px solid #1E3050",
          cursor:"pointer",transition:"all 0.3s ease",
          animation:`fadeUp 0.3s ease ${i*0.05}s both`
        }}>
          {/* Main row */}
          <div style={{display:"flex",alignItems:"center",gap:12}}>
            {/* Rank */}
            <div style={{width:32,textAlign:"center",flexShrink:0}}>
              {rank===1?<span style={{fontSize:28}}>👑</span>:rank===2?<span style={{fontSize:22}}>🥈</span>:rank===3?<span style={{fontSize:22}}>🥉</span>:<span style={{fontSize:18,color:"#7B8CA8",fontWeight:800,fontFamily:"'Oswald',sans-serif"}}>{rank}</span>}
            </div>
            {/* Avatar */}
            <PlayerAv player={p} avatars={avatars} size={isTop3?52:44} isChamp={champ&&p.id===champ.currentOwner} />
            {/* Name + bar */}
            <div style={{flex:1,minWidth:0}}>
              <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:4,flexWrap:"wrap"}}>
                <span style={{fontSize:isTop3?20:17,fontWeight:800,color:"#fff"}}>{p.name}</span>
                {isMe&&<span style={{fontSize:10,fontWeight:700,color:p.color,background:`${p.color}20`,padding:"1px 6px",borderRadius:8,letterSpacing:1}}>YOU</span>}
                {p.streak>=2&&<span style={{display:"inline-flex",alignItems:"center",gap:2,background:p.streak>=4?"#FF6B3530":"#FF6B3515",borderRadius:12,padding:"2px 8px",border:p.streak>=4?"1px solid #FF6B3550":"none",fontSize:12,fontWeight:800,color:"#FF6B35"}}>🔥{p.streak}</span>}
                {p.stolen>0&&<span style={{display:"inline-flex",alignItems:"center",gap:2,background:"#A855F720",borderRadius:12,padding:"2px 8px",fontSize:12,fontWeight:800,color:"#A855F7"}}>⚔️{p.stolen}</span>}
              </div>
              <div style={{display:"flex",alignItems:"center",gap:8}}>
                <div style={{position:"relative",height:6,background:"#1E3050",borderRadius:3,overflow:"hidden",flex:1}}>
                  <div style={{width:`${pct/maxPct*100}%`,height:"100%",background:rank===1?`linear-gradient(90deg,${p.color},#FFD700)`:p.color,borderRadius:3,transition:"width 1.2s cubic-bezier(0.34,1.56,0.64,1)",boxShadow:isTop3?`0 0 8px ${p.color}60`:"none"}} />
                </div>
                <span style={{fontSize:14,fontWeight:800,color:p.color,fontFamily:"'Oswald',sans-serif",minWidth:50,textAlign:"right"}}>{pct}%</span>
              </div>
            </div>
            {/* Alive count */}
            <div style={{textAlign:"center",flexShrink:0}}>
              <div style={{fontSize:24,fontWeight:900,color:p.alive>6?"#00D4AA":p.alive>4?"#FBBF24":p.alive>0?"#FF4757":"#7B8CA850",fontFamily:"'Oswald',sans-serif"}}>{p.alive}</div>
              <div style={{fontSize:10,color:"#7B8CA8",fontWeight:700,letterSpacing:1}}>{p.alive===0?"OUT":"ALIVE"}</div>
              {i>0&&ranks[i-1].alive===p.alive&&p.alive>0&&<div style={{fontSize:10,color:"#FBBF24",fontWeight:700,marginTop:2}}>TB:{p.best}</div>}
            </div>
          </div>
          {/* Team logos — always visible */}
          {aliveTeams.length>0&&<div style={{display:"flex",gap:4,marginTop:10,flexWrap:"wrap",alignItems:"center"}}>
            {aliveTeams.map(t=><div key={t.id} onClick={e=>{e.stopPropagation();onTeam&&onTeam(t);}} style={{cursor:"pointer"}}><Logo name={t.name} size={22} /></div>)}
          </div>}
          {/* Expanded: team names */}
          {isExp&&<div style={{marginTop:10,paddingTop:10,borderTop:"1px solid #1E3050",display:"flex",flexWrap:"wrap",gap:6,animation:"fadeUp 0.3s ease both"}}>
            {aliveTeams.map(t=><div key={t.id} onClick={e=>{e.stopPropagation();onTeam&&onTeam(t);}} style={{background:"#0B1120",borderRadius:8,padding:"4px 10px",fontSize:12,fontWeight:600,color:"#B8C5D4",border:"1px solid #1E3050",cursor:"pointer",display:"flex",alignItems:"center",gap:4}}>
              <Logo name={t.name} size={16}/>{t.name}{t.originalOwner!==t.currentOwner&&<span style={{color:"#A855F7",fontSize:10}}>STOLE</span>}
            </div>)}
          </div>}
        </div>;
      })}

      {/* Copy + rules */}
      <button onClick={()=>{const txt=`🏀 MARCH MAYHEM — ${RDS[state.currentRound]}\n${ranks.map((p,i)=>`${i+1}. ${p.name}: ${p.alive} alive`).join("\n")}`;navigator.clipboard?.writeText(txt).then(()=>{}).catch(()=>{});}} style={{...B("#1E3050","#B8C5D4"),width:"100%",marginTop:16,fontSize:16}}>📋 Copy Standings</button>
      <div style={{background:"#131D2F",borderRadius:8,padding:12,marginTop:12,textAlign:"center",fontSize:13,color:"#7B8CA8"}}>Spread winner controls the advancing team. Tiebreaker: best remaining seed (lower = better). Control the champion to win.</div>
    </div>
  );
}

// --- TEAM DETAIL DRAWER — tap any team to see full history ---
function TeamDetail({ team, state, onClose }) {
  const t = team;
  const orig = state.players[t.originalOwner];
  const curr = state.players[t.currentOwner];
  const RDS = ["Round 1","Round 2","Sweet 16","Elite 8","Final Four","Championship"];
  
  // Build ownership chain from game history
  const chain = [];
  chain.push({ owner: orig, event: "Drafted", round: "Draft", color: orig.color });
  
  const teamGames = state.games.filter(g => g.completed && g.transferInfo && (g.team1Id === t.id || g.team2Id === t.id)).sort((a, b) => a.round - b.round);
  
  teamGames.forEach(g => {
    const ti = g.transferInfo;
    const won = g.winnerId === t.id;
    const opp = state.teams.find(x => x.id === (g.team1Id === t.id ? g.team2Id : g.team1Id));
    const oppOwner = opp ? state.players[opp.originalOwner] : null;
    const sp = Math.abs(g.spread || 0);
    
    if (won) {
      if (ti.stolen && ti.advancer === t.name) {
        const newOwner = state.players.find(p => p.name === ti.to);
        chain.push({
          owner: newOwner,
          event: "STOLEN from " + ti.from,
          round: RDS[g.round] || "",
          detail: "vs " + (opp?.name || "?") + " | won by " + g.margin + ", spread " + sp,
          color: "#FF4757",
          stolen: true
        });
      } else {
        const keeper = state.players.find(p => p.name === ti.to);
        chain.push({
          owner: keeper,
          event: ti.to + " keeps control",
          round: RDS[g.round] || "",
          detail: "vs " + (opp?.name || "?") + " | won by " + g.margin + ", spread " + sp,
          color: "#00D4AA",
          stolen: false
        });
      }
    }
  });
  
  if (!t.alive) {
    chain.push({ owner: null, event: "ELIMINATED", round: RDS[t.eliminatedRound || 0], color: "#FF4757", dead: true });
  }
  
  return (
    <div onClick={onClose} style={{position:"fixed",inset:0,zIndex:200,background:"rgba(0,0,0,0.85)",display:"flex",alignItems:"flex-end",justifyContent:"center",cursor:"pointer",animation:"fadeUp 0.2s ease both"}}>
      <div onClick={e=>e.stopPropagation()} style={{background:"#131D2F",borderRadius:"20px 20px 0 0",width:"100%",maxWidth:500,maxHeight:"85vh",overflowY:"auto",padding:24,cursor:"default"}}>
        {/* Header */}
        <div style={{display:"flex",alignItems:"center",gap:14,marginBottom:20}}>
          <Logo name={t.name} size={52} />
          <div style={{flex:1}}>
            <div style={{fontSize:24,fontWeight:900,color:"#fff",fontFamily:"'Oswald',sans-serif"}}>{t.name}</div>
            <div style={{fontSize:14,color:"#7B8CA8"}}>({t.seed}) seed • {t.region}</div>
          </div>
          <div style={{fontSize:28}}>{t.alive ? "🟢" : "💀"}</div>
        </div>
        
        {/* Current owner */}
        <div style={{display:"flex",alignItems:"center",gap:10,padding:"12px 14px",background:"#0B1120",borderRadius:10,marginBottom:20,border:`1px solid ${curr.color}40`}}>
          <PlayerAv player={curr} avatars={{}} size={36} />
          <div>
            <div style={{fontSize:11,color:"#7B8CA8",letterSpacing:1}}>CONTROLLED BY</div>
            <div style={{fontSize:18,fontWeight:700,color:curr.color}}>{curr.name}{t.originalOwner !== t.currentOwner ? " (stolen)" : " (drafted)"}</div>
          </div>
        </div>

        {/* Ownership Chain */}
        <div style={{fontSize:12,color:"#7B8CA8",letterSpacing:2,fontWeight:700,marginBottom:12}}>OWNERSHIP CHAIN</div>
        <div style={{position:"relative",paddingLeft:24,marginBottom:20}}>
          {/* Vertical line */}
          <div style={{position:"absolute",left:8,top:8,bottom:8,width:2,background:"#1E3050"}} />
          
          {chain.map((step, i) => (
            <div key={i} style={{position:"relative",marginBottom:i<chain.length-1?16:0,animation:`fadeUp 0.3s ease ${i*0.1}s both`}}>
              {/* Dot */}
              <div style={{position:"absolute",left:-20,top:4,width:14,height:14,borderRadius:"50%",background:step.dead?"#FF4757":step.stolen?"#A855F7":"#0B1120",border:`2px solid ${step.color}`,zIndex:1}} />
              
              {/* Content */}
              <div style={{background:step.stolen?"#FF475710":step.dead?"#FF475708":"transparent",borderRadius:8,padding:step.detail?"10px 12px":"4px 0"}}>
                <div style={{display:"flex",alignItems:"center",gap:8}}>
                  <span style={{fontSize:11,color:"#7B8CA8",fontWeight:600,minWidth:60}}>{step.round}</span>
                  <span style={{fontSize:14,fontWeight:700,color:step.dead?"#FF4757":step.stolen?"#A855F7":"#fff"}}>
                    {step.dead?"💀 Eliminated":step.stolen?"⚔️ "+step.event:"✅ "+step.event}
                  </span>
                </div>
                {step.detail&&<div style={{fontSize:12,color:"#7B8CA8",marginTop:3,marginLeft:68}}>{step.detail}</div>}
              </div>
            </div>
          ))}
        </div>
        
        {/* Game history */}
        {teamGames.length > 0 && <>
          <div style={{fontSize:12,color:"#7B8CA8",letterSpacing:2,fontWeight:700,marginBottom:12}}>GAME LOG</div>
          {teamGames.map((g, i) => {
            const won = g.winnerId === t.id;
            const opp = state.teams.find(x => x.id === (g.team1Id === t.id ? g.team2Id : g.team1Id));
            const ti = g.transferInfo;
            return (
              <div key={i} style={{display:"flex",alignItems:"center",gap:10,padding:"8px 0",borderBottom:"1px solid #1E3050"}}>
                <div style={{fontSize:18}}>{won ? "✅" : "💀"}</div>
                <Logo name={opp?.name} size={24} />
                <div style={{flex:1}}>
                  <div style={{fontSize:14,fontWeight:600,color:"#fff"}}>{won?"Beat":"Lost to"} {opp?.name}</div>
                  <div style={{fontSize:12,color:"#7B8CA8"}}>{RDS[g.round]} • {g.margin} pts • spread {Math.abs(g.spread||0)}</div>
                </div>
                {ti?.stolen && won && <span style={{fontSize:11,color:"#A855F7",fontWeight:700,background:"#A855F720",padding:"2px 8px",borderRadius:8}}>STOLEN</span>}
              </div>
            );
          })}
        </>}
        
        <button onClick={onClose} style={{width:"100%",marginTop:20,padding:14,background:"#1E3050",border:"none",borderRadius:10,color:"#7B8CA8",fontSize:16,fontWeight:700,cursor:"pointer"}}>Close</button>
      </div>
    </div>
  );
}

// --- SHARED ---
